-- BEGIN FRAGMENT: 002b_cql.sql
CREATE OR REPLACE FUNCTION parse_dtrange(
    _indate jsonb,
    relative_base timestamptz DEFAULT date_trunc('hour', CURRENT_TIMESTAMP)
) RETURNS tstzrange AS $$
DECLARE
    timestrs text[];
    s timestamptz;
    e timestamptz;
BEGIN
    timestrs :=
    CASE
        WHEN _indate ? 'timestamp' THEN
            ARRAY[_indate->>'timestamp']
        WHEN _indate ? 'interval' THEN
            to_text_array(_indate->'interval')
        WHEN jsonb_typeof(_indate) = 'array' THEN
            to_text_array(_indate)
        ELSE
            regexp_split_to_array(
                _indate->>0,
                '/'
            )
    END;
    RAISE NOTICE 'TIMESTRS %', timestrs;
    IF cardinality(timestrs) = 1 THEN
        IF timestrs[1] ILIKE 'P%' THEN
            RETURN tstzrange(relative_base - upper(timestrs[1])::interval, relative_base, '[)');
        END IF;
        s := timestrs[1]::timestamptz;
        RETURN tstzrange(s, s, '[]');
    END IF;

    IF cardinality(timestrs) != 2 THEN
        RAISE EXCEPTION 'Timestamp cannot have more than 2 values';
    END IF;

    IF timestrs[1] = '..' OR timestrs[1] = '' THEN
        s := '-infinity'::timestamptz;
        e := timestrs[2]::timestamptz;
        RETURN tstzrange(s,e,'[)');
    END IF;

    IF timestrs[2] = '..' OR timestrs[2] = '' THEN
        s := timestrs[1]::timestamptz;
        e := 'infinity'::timestamptz;
        RETURN tstzrange(s,e,'[)');
    END IF;

    IF timestrs[1] ILIKE 'P%' AND timestrs[2] NOT ILIKE 'P%' THEN
        e := timestrs[2]::timestamptz;
        s := e - upper(timestrs[1])::interval;
        RETURN tstzrange(s,e,'[)');
    END IF;

    IF timestrs[2] ILIKE 'P%' AND timestrs[1] NOT ILIKE 'P%' THEN
        s := timestrs[1]::timestamptz;
        e := s + upper(timestrs[2])::interval;
        RETURN tstzrange(s,e,'[)');
    END IF;

    s := timestrs[1]::timestamptz;
    e := timestrs[2]::timestamptz;

    RETURN tstzrange(s,e,'[)');

    RETURN NULL;

END;
$$ LANGUAGE PLPGSQL STABLE STRICT PARALLEL SAFE SET TIME ZONE 'UTC';

CREATE OR REPLACE FUNCTION parse_dtrange(
    _indate text,
    relative_base timestamptz DEFAULT CURRENT_TIMESTAMP
) RETURNS tstzrange AS $$
    SELECT parse_dtrange(to_jsonb(_indate), relative_base);
$$ LANGUAGE SQL STABLE STRICT PARALLEL SAFE;


CREATE OR REPLACE FUNCTION temporal_op_query(op text, args jsonb) RETURNS text AS $$
DECLARE
    ll text := 'datetime';
    lh text := 'end_datetime';
    rrange tstzrange;
    rl text;
    rh text;
    outq text;
BEGIN
    rrange := parse_dtrange(args->1);
    op := lower(op);
    rl := format('%L::timestamptz', lower(rrange));
    rh := format('%L::timestamptz', upper(rrange));
    outq := CASE op
        WHEN 't_before'       THEN 'lh < rl'
        WHEN 't_after'        THEN 'll > rh'
        WHEN 't_meets'        THEN 'lh = rl'
        WHEN 't_metby'        THEN 'll = rh'
        WHEN 't_overlaps'     THEN 'll < rl AND rl < lh < rh'
        WHEN 't_overlappedby' THEN 'rl < ll < rh AND lh > rh'
        WHEN 't_starts'       THEN 'll = rl AND lh < rh'
        WHEN 't_startedby'    THEN 'll = rl AND lh > rh'
        WHEN 't_during'       THEN 'll > rl AND lh < rh'
        WHEN 't_contains'     THEN 'll < rl AND lh > rh'
        WHEN 't_finishes'     THEN 'll > rl AND lh = rh'
        WHEN 't_finishedby'   THEN 'll < rl AND lh = rh'
        WHEN 't_equals'       THEN 'll = rl AND lh = rh'
        WHEN 't_disjoint'     THEN 'NOT (ll <= rh AND lh >= rl)'
        WHEN 't_intersects'   THEN 'll <= rh AND lh >= rl'
        WHEN 'anyinteracts'   THEN 'll <= rh AND lh >= rl'
    END;
    outq := regexp_replace(outq, '\mll\M', ll);
    outq := regexp_replace(outq, '\mlh\M', lh);
    outq := regexp_replace(outq, '\mrl\M', rl);
    outq := regexp_replace(outq, '\mrh\M', rh);
    outq := format('(%s)', outq);
    RETURN outq;
END;
$$ LANGUAGE PLPGSQL STABLE STRICT;



CREATE OR REPLACE FUNCTION spatial_op_query(op text, args jsonb) RETURNS text AS $$
DECLARE
    geom text;
    j jsonb := args->1;
BEGIN
    op := lower(op);
    IF op NOT IN ('s_equals','s_disjoint','s_touches','s_within','s_overlaps','s_crosses','s_intersects','intersects','s_contains') THEN
        RAISE EXCEPTION 'Spatial Operator % Not Supported', op;
    END IF;
    op := regexp_replace(op, '^s_', 'st_');
    IF op = 'intersects' THEN
        op := 'st_intersects';
    END IF;
    -- Convert geometry to WKB string
    IF j ? 'type' AND j ? 'coordinates' THEN
        geom := st_geomfromgeojson(j)::text;
    ELSIF jsonb_typeof(j) = 'array' THEN
        geom := bbox_geom(j)::text;
    END IF;

    RETURN format('%s(geometry, %L::geometry)', op, geom);
END;
$$ LANGUAGE PLPGSQL;

-- q_op_query: SQL predicate for the pgstac `q` full-text operator. args is the search
-- term(s) (a string or array of strings, as the STAC `q` parameter); it is matched
-- against a tsvector built from the item's description/title/keywords. Modeled on
-- spatial_op_query / temporal_op_query so full-text is a first-class CQL2 op and the
-- whole search predicate has a single CQL2 representation.
CREATE OR REPLACE FUNCTION q_op_query(args jsonb) RETURNS text AS $$
    SELECT format(
        $q$(
            to_tsvector('english', coalesce(properties->>'description', '')) ||
            to_tsvector('english', coalesce(properties->>'title', '')) ||
            to_tsvector('english', coalesce(properties->>'keywords', ''))
        ) @@ %L$q$,
        q_to_tsquery(args)
    );
$$ LANGUAGE SQL STABLE;

CREATE OR REPLACE FUNCTION query_to_cql2(q jsonb) RETURNS jsonb AS $$
-- Translates anything passed in through the deprecated "query" into equivalent CQL2
WITH t AS (
    SELECT key as property, value as ops
        FROM jsonb_each(q)
), t2 AS (
    SELECT property, (jsonb_each(ops)).*
        FROM t WHERE jsonb_typeof(ops) = 'object'
    UNION ALL
    SELECT property, 'eq', ops
        FROM t WHERE jsonb_typeof(ops) != 'object'
)
SELECT
    jsonb_strip_nulls(jsonb_build_object(
        'op', 'and',
        'args', jsonb_agg(
            jsonb_build_object(
                'op', key,
                'args', jsonb_build_array(
                    jsonb_build_object('property',property),
                    value
                )
            )
        )
    )
) as qcql FROM t2
;
$$ LANGUAGE SQL IMMUTABLE STRICT;


CREATE OR REPLACE FUNCTION cql1_to_cql2(j jsonb) RETURNS jsonb AS $$
DECLARE
    args jsonb;
    ret jsonb;
BEGIN
    RAISE NOTICE 'CQL1_TO_CQL2: %', j;
    IF j ? 'filter' THEN
        RETURN cql1_to_cql2(j->'filter');
    END IF;
    IF j ? 'property' THEN
        RETURN j;
    END IF;
    IF jsonb_typeof(j) = 'array' THEN
        SELECT jsonb_agg(cql1_to_cql2(el)) INTO args FROM jsonb_array_elements(j) el;
        RETURN args;
    END IF;
    IF jsonb_typeof(j) = 'number' THEN
        RETURN j;
    END IF;
    IF jsonb_typeof(j) = 'string' THEN
        RETURN j;
    END IF;

    IF jsonb_typeof(j) = 'object' THEN
        SELECT jsonb_build_object(
                'op', key,
                'args', cql1_to_cql2(value)
            ) INTO ret
        FROM jsonb_each(j)
        WHERE j IS NOT NULL;
        RETURN ret;
    END IF;
    RETURN NULL;
END;
$$ LANGUAGE PLPGSQL IMMUTABLE STRICT;

CREATE TABLE cql2_ops (
    op text PRIMARY KEY,
    template text,
    types text[]
);
INSERT INTO cql2_ops (op, template, types) VALUES
    ('eq', '%s = %s', NULL),
    ('neq', '%s != %s', NULL),
    ('ne', '%s != %s', NULL),
    ('!=', '%s != %s', NULL),
    ('<>', '%s != %s', NULL),
    ('lt', '%s < %s', NULL),
    ('lte', '%s <= %s', NULL),
    ('gt', '%s > %s', NULL),
    ('gte', '%s >= %s', NULL),
    ('le', '%s <= %s', NULL),
    ('ge', '%s >= %s', NULL),
    ('=', '%s = %s', NULL),
    ('<', '%s < %s', NULL),
    ('<=', '%s <= %s', NULL),
    ('>', '%s > %s', NULL),
    ('>=', '%s >= %s', NULL),
    ('like', '%s LIKE %s', NULL),
    ('ilike', '%s ILIKE %s', NULL),
    ('+', '%s + %s', NULL),
    ('-', '%s - %s', NULL),
    ('*', '%s * %s', NULL),
    ('/', '%s / %s', NULL),
    ('not', 'NOT (%s)', NULL),
    ('between', '%s BETWEEN %s AND %s', NULL),
    ('isnull', '%s IS NULL', NULL),
    ('upper', 'upper(%s)', NULL),
    ('lower', 'lower(%s)', NULL),
    ('casei', 'upper(%s)', NULL),
    ('accenti', 'unaccent(%s)', NULL)
ON CONFLICT (op) DO UPDATE
    SET
        template = EXCLUDED.template
;


CREATE OR REPLACE FUNCTION cql2_query(j jsonb, wrapper text DEFAULT NULL) RETURNS text AS $$
#variable_conflict use_variable
DECLARE
    args jsonb := j->'args';
    arg jsonb;
    op text := lower(j->>'op');
    cql2op RECORD;
    literal text;
    _wrapper text;
    leftarg text;
    rightarg text;
    prop text;
    extra_props bool := pgstac.additional_properties();
    queryable_row RECORD;
BEGIN
    IF j IS NULL OR (op IS NOT NULL AND args IS NULL) THEN
        RETURN NULL;
    END IF;

    -- check if all properties are represented in the queryables
    IF NOT extra_props THEN
        FOR prop IN
            SELECT DISTINCT p->>0
            FROM jsonb_path_query(j, 'strict $.**.property') p
            WHERE p->>0 NOT IN ('id', 'datetime', 'geometry', 'end_datetime', 'collection')
        LOOP
            IF (queryable(prop)).nulled_wrapper IS NULL THEN
                RAISE EXCEPTION 'Term % is not found in queryables.', prop;
            END IF;
        END LOOP;
    END IF;

    IF j ? 'filter' THEN
        RETURN cql2_query(j->'filter');
    END IF;

    IF j ? 'upper' THEN
        RETURN  cql2_query(jsonb_build_object('op', 'upper', 'args', j->'upper'));
    END IF;

    IF j ? 'lower' THEN
        RETURN  cql2_query(jsonb_build_object('op', 'lower', 'args', j->'lower'));
    END IF;

    -- Temporal Query
    IF op ilike 't_%' or op = 'anyinteracts' THEN
        RETURN temporal_op_query(op, args);
    END IF;

    -- If property is a timestamp convert it to text to use with
    -- general operators
    IF j ? 'timestamp' THEN
        RETURN format('%L::timestamptz', to_tstz(j->'timestamp'));
    END IF;
    IF j ? 'interval' THEN
        RAISE EXCEPTION 'Please use temporal operators when using intervals.';
    END IF;

    -- Spatial Query
    IF op ilike 's_%' or op = 'intersects' THEN
        RETURN spatial_op_query(op, args);
    END IF;

    -- Full-text Query (pgstac `q` operator)
    IF op = 'q' THEN
        RETURN q_op_query(args);
    END IF;

    IF op IN ('a_equals','a_contains','a_contained_by','a_overlaps') THEN
        IF args->0 ? 'property' THEN
            leftarg := format('to_text_array(%s)', (queryable(args->0->>'property')).path);
        END IF;
        IF args->1 ? 'property' THEN
            rightarg := format('to_text_array(%s)', (queryable(args->1->>'property')).path);
        END IF;
        RETURN FORMAT(
            '%s %s %s',
            COALESCE(leftarg, quote_literal(to_text_array(args->0))),
            CASE op
                WHEN 'a_equals' THEN '='
                WHEN 'a_contains' THEN '@>'
                WHEN 'a_contained_by' THEN '<@'
                WHEN 'a_overlaps' THEN '&&'
            END,
            COALESCE(rightarg, quote_literal(to_text_array(args->1)))
        );
    END IF;

    IF op = 'in' THEN
        RAISE NOTICE 'IN : % % %', args, jsonb_build_array(args->0), args->1;
        args := jsonb_build_array(args->0) || (args->1);
        RAISE NOTICE 'IN2 : %', args;
    END IF;



    IF op = 'between' THEN
        args = jsonb_build_array(
            args->0,
            args->1,
            args->2
        );
    END IF;

    -- Make sure that args is an array and run cql2_query on
    -- each element of the array
    RAISE NOTICE 'ARGS PRE: %', args;
    IF j ? 'args' THEN
        IF jsonb_typeof(args) != 'array' THEN
            args := jsonb_build_array(args);
        END IF;

        IF jsonb_path_exists(args, '$[*] ? (@.property == "id" || @.property == "datetime" || @.property == "end_datetime" || @.property == "collection")') THEN
            wrapper := NULL;
        ELSE
            -- if any of the arguments are a property, try to get the property_wrapper
            FOR arg IN SELECT jsonb_path_query(args, '$[*] ? (@.property != null)') LOOP
                RAISE NOTICE 'Arg: %', arg;
                wrapper := (queryable(arg->>'property')).nulled_wrapper;
                RAISE NOTICE 'Property: %, Wrapper: %', arg, wrapper;
                IF wrapper IS NOT NULL THEN
                    EXIT;
                END IF;
            END LOOP;

            -- if the property was not in queryables, see if any args were numbers
            IF
                wrapper IS NULL
                AND jsonb_path_exists(args, '$[*] ? (@.type()=="number")')
            THEN
                wrapper := 'to_float';
            END IF;
            wrapper := coalesce(wrapper, 'to_text');
        END IF;

        SELECT jsonb_agg(cql2_query(a, wrapper))
            INTO args
        FROM jsonb_array_elements(args) a;
    END IF;
    RAISE NOTICE 'ARGS: %', args;

    IF op IN ('and', 'or') THEN
        RETURN
            format(
                '(%s)',
                array_to_string(to_text_array(args), format(' %s ', upper(op)))
            );
    END IF;

    IF op = 'in' THEN
        RAISE NOTICE 'IN --  % %', args->0, to_text(args->0);
        RETURN format(
            '%s IN (%s)',
            to_text(args->0),
            array_to_string((to_text_array(args))[2:], ',')
        );
    END IF;

    -- Look up template from cql2_ops
    IF j ? 'op' THEN
        SELECT * INTO cql2op FROM cql2_ops WHERE  cql2_ops.op ilike op;
        IF FOUND THEN
            -- If specific index set in queryables for a property cast other arguments to that type

            RETURN format(
                cql2op.template,
                VARIADIC (to_text_array(args))
            );
        ELSE
            RAISE EXCEPTION 'Operator % Not Supported.', op;
        END IF;
    END IF;


    IF wrapper IS NOT NULL THEN
        RAISE NOTICE 'Wrapping % with %', j, wrapper;
        IF j ? 'property' THEN
            SELECT * INTO queryable_row FROM queryable(j->>'property');
            -- For native promoted columns (expression = path, no JSONB extraction),
            -- the column's type already matches; applying a cast wrapper like to_int()
            -- is redundant and prevents index-only scans.  Return the bare expression.
            IF
                wrapper = ANY (ARRAY['to_int', 'to_float', 'to_tstz', 'to_text', 'to_text_array'])
                AND queryable_row.expression = queryable_row.path
            THEN
                RETURN queryable_row.expression;
            END IF;
            RETURN format('%I(%s)', wrapper, queryable_row.path);
        ELSE
            RETURN format('%I(%L)', wrapper, j);
        END IF;
    ELSIF j ? 'property' THEN
        RETURN quote_ident(j->>'property');
    END IF;

    RETURN quote_literal(to_text(j));
END;
$$ LANGUAGE PLPGSQL STABLE;


CREATE OR REPLACE FUNCTION paging_dtrange(
    j jsonb
) RETURNS tstzrange AS $$
DECLARE
    op text;
    filter jsonb := j->'filter';
    dtrange tstzrange := tstzrange('-infinity'::timestamptz,'infinity'::timestamptz);
    sdate timestamptz := '-infinity'::timestamptz;
    edate timestamptz := 'infinity'::timestamptz;
    jpitem jsonb;
BEGIN

    IF j ? 'datetime' THEN
        dtrange := parse_dtrange(j->'datetime');
        sdate := lower(dtrange);
        edate := upper(dtrange);
    END IF;
    IF NOT (filter  @? '$.**.op ? (@ == "or" || @ == "not")') THEN
        FOR jpitem IN SELECT jpval FROM jsonb_path_query(filter,'strict $.** ? (@.args[*].property == "datetime")'::jsonpath) AS jp(jpval) LOOP
            op := lower(jpitem->>'op');
            dtrange := parse_dtrange(jpitem->'args'->1);
            IF op IN ('<=', 'lt', 'lte', '<', 'le', 't_before') THEN
                sdate := greatest(sdate,'-infinity');
                edate := least(edate, upper(dtrange));
            ELSIF op IN ('>=', '>', 'gt', 'gte', 'ge', 't_after') THEN
                edate := least(edate, 'infinity');
                sdate := greatest(sdate, lower(dtrange));
            ELSIF op IN ('=', 'eq') THEN
                edate := least(edate, upper(dtrange));
                sdate := greatest(sdate, lower(dtrange));
            END IF;
            RAISE NOTICE '2 OP: %, ARGS: %, DTRANGE: %, SDATE: %, EDATE: %', op, jpitem->'args'->1, dtrange, sdate, edate;
        END LOOP;
    END IF;
    IF sdate > edate THEN
        RETURN 'empty'::tstzrange;
    END IF;
    RETURN tstzrange(sdate,edate, '[]');
END;
$$ LANGUAGE PLPGSQL STABLE STRICT SET TIME ZONE 'UTC';

-- ============================================================================
-- Predicate envelope: a safe over-approximation of the (datetime, end_datetime,
-- geometry) any matching row must fall within, derived from the FULL search
-- predicate. Used by chunker() (004_search.sql) to prune partition candidates by an
-- indexed range query. tstzmultirange keeps OR of disjoint ranges tight;
-- AND = intersect, OR = hull/union, NOT/unknown = full (never a false negative).
-- ============================================================================
DO $$ BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname='pred_envelope'
                   AND typnamespace=(SELECT oid FROM pg_namespace WHERE nspname='pgstac')) THEN
        -- colls: allowed collection set (NULL = all, '{}' = none); dt/edt: allowed
        -- item datetime/end_datetime; geom: spatial bbox bound (NULL = unconstrained).
        CREATE TYPE pred_envelope AS (colls text[], dt tstzmultirange, edt tstzmultirange, geom geometry);
    END IF;
END $$;

CREATE OR REPLACE FUNCTION env_full() RETURNS pred_envelope LANGUAGE sql IMMUTABLE AS $$
    SELECT (NULL::text[],
            tstzmultirange(tstzrange('-infinity','infinity','[]')),
            tstzmultirange(tstzrange('-infinity','infinity','[]')), NULL)::pred_envelope;
$$;

-- AND: intersect every axis (tighter is safe -- a row must satisfy both). For colls,
-- NULL means unconstrained, so AND with NULL keeps the other side; two sets intersect
-- (an empty result '{}' means no collection can match -> no partitions).
CREATE OR REPLACE FUNCTION env_and(a pred_envelope, b pred_envelope) RETURNS pred_envelope LANGUAGE sql IMMUTABLE AS $$
    SELECT (
            CASE WHEN a.colls IS NULL THEN b.colls WHEN b.colls IS NULL THEN a.colls
                 ELSE array_intersection(a.colls, b.colls) END,
            a.dt * b.dt, a.edt * b.edt,
            CASE WHEN a.geom IS NULL THEN b.geom WHEN b.geom IS NULL THEN a.geom
                 ELSE ST_Envelope(ST_Intersection(a.geom, b.geom)) END)::pred_envelope;
$$;

-- OR: union every axis (wider). For colls, if either side is unconstrained (NULL) the
-- union is unconstrained; otherwise it is the de-duplicated union of the two sets.
CREATE OR REPLACE FUNCTION env_or(a pred_envelope, b pred_envelope) RETURNS pred_envelope LANGUAGE sql IMMUTABLE AS $$
    SELECT (
            CASE WHEN a.colls IS NULL OR b.colls IS NULL THEN NULL
                 ELSE ARRAY(SELECT DISTINCT unnest(a.colls || b.colls)) END,
            a.dt + b.dt, a.edt + b.edt,
            CASE WHEN a.geom IS NULL OR b.geom IS NULL THEN NULL
                 ELSE ST_Envelope(ST_Collect(a.geom, b.geom)) END)::pred_envelope;
$$;

-- coerce a cql2 scalar (string | {"timestamp":..} | {"date":..}) to timestamptz
CREATE OR REPLACE FUNCTION cql2_ts(v jsonb) RETURNS timestamptz LANGUAGE sql IMMUTABLE AS $$
    SELECT coalesce(v->>'timestamp', v->>'date', v#>>'{}')::timestamptz;
$$;

-- Resolve a cql2 predicate on the `collection` property to an allowed collection SET.
-- =/in are exact; </<=/>/>=/between/like/ilike are resolved against the live collections
-- table (an empty match returns '{}' = no collection qualifies). NULL = could not bound
-- (treated as unconstrained). STABLE (reads collections).
CREATE OR REPLACE FUNCTION cql2_collection_set(op text, args jsonb) RETURNS text[] LANGUAGE plpgsql STABLE AS $$
DECLARE lst jsonb;
BEGIN
    IF op IN ('=','eq') AND jsonb_typeof(args->1) = 'string' THEN
        RETURN ARRAY[args->>1];
    ELSIF op = 'in' THEN
        lst := CASE WHEN jsonb_typeof(args->1)='object' AND args->1 ? 'list' THEN args->1->'list' ELSE args->1 END;
        IF jsonb_typeof(lst) <> 'array' THEN RETURN NULL; END IF;
        RETURN to_text_array(lst);
    ELSIF jsonb_typeof(args->1) = 'string' THEN
        IF    op IN ('<','lt')   THEN RETURN coalesce((SELECT array_agg(id) FROM collections WHERE id <  (args->>1)), '{}');
        ELSIF op IN ('<=','lte') THEN RETURN coalesce((SELECT array_agg(id) FROM collections WHERE id <= (args->>1)), '{}');
        ELSIF op IN ('>','gt')   THEN RETURN coalesce((SELECT array_agg(id) FROM collections WHERE id >  (args->>1)), '{}');
        ELSIF op IN ('>=','gte') THEN RETURN coalesce((SELECT array_agg(id) FROM collections WHERE id >= (args->>1)), '{}');
        ELSIF op IN ('like')     THEN RETURN coalesce((SELECT array_agg(id) FROM collections WHERE id LIKE  (args->>1)), '{}');
        ELSIF op IN ('ilike')    THEN RETURN coalesce((SELECT array_agg(id) FROM collections WHERE id ILIKE (args->>1)), '{}');
        END IF;
    ELSIF op = 'between' AND jsonb_typeof(args->1)='string' AND jsonb_typeof(args->2)='string' THEN
        RETURN coalesce((SELECT array_agg(id) FROM collections WHERE id BETWEEN (args->>1) AND (args->>2)), '{}');
    END IF;
    RETURN NULL;        -- unsupported shape -> unconstrained
END;
$$;

-- Recursive envelope of a normalized cql2 filter tree.
-- STABLE (not IMMUTABLE): parse_dtrange + cql2_collection_set are STABLE.
CREATE OR REPLACE FUNCTION cql2_envelope(j jsonb) RETURNS pred_envelope LANGUAGE plpgsql STABLE AS $$
DECLARE op text; args jsonb; child jsonb; acc pred_envelope; r tstzrange; prop text; v timestamptz; g geometry;
BEGIN
    IF j IS NULL OR jsonb_typeof(j) <> 'object' OR NOT j ? 'op' THEN RETURN env_full(); END IF;
    op := lower(j->>'op'); args := j->'args';
    IF op = 'and' THEN
        acc := env_full();
        FOR child IN SELECT * FROM jsonb_array_elements(args) LOOP acc := env_and(acc, cql2_envelope(child)); END LOOP;
        RETURN acc;
    ELSIF op = 'or' THEN
        acc := NULL;
        FOR child IN SELECT * FROM jsonb_array_elements(args) LOOP
            acc := CASE WHEN acc IS NULL THEN cql2_envelope(child) ELSE env_or(acc, cql2_envelope(child)) END;
        END LOOP;
        RETURN coalesce(acc, env_full());
    ELSIF op = 'not' THEN
        RETURN env_full();                                       -- negation can't be safely tightened
    ELSIF op ILIKE 't_%' OR op = 'anyinteracts' THEN
        r := parse_dtrange(args->1); acc := env_full();
        IF op IN ('t_intersects','anyinteracts','t_during','t_equals','t_starts','t_finishes','t_overlaps') THEN
            acc.dt  := tstzmultirange(tstzrange('-infinity', upper(r), '(]'));   -- datetime <= rh
            acc.edt := tstzmultirange(tstzrange(lower(r), 'infinity', '[)'));    -- end_datetime >= rl
        ELSIF op IN ('t_before','t_meets') THEN
            acc.edt := tstzmultirange(tstzrange('-infinity', lower(r), '()'));
        ELSIF op IN ('t_after','t_metby') THEN
            acc.dt  := tstzmultirange(tstzrange(upper(r), 'infinity', '()'));
        END IF;
        RETURN acc;
    ELSIF op ILIKE 's_%' OR op = 'intersects' THEN
        BEGIN g := ST_GeomFromGeoJSON(args->1); EXCEPTION WHEN others THEN g := NULL; END;
        acc := env_full(); acc.geom := ST_Envelope(g); RETURN acc;
    ELSIF op IN ('=','<','<=','>','>=','between','eq','lt','lte','gt','gte','in','like','ilike')
          AND jsonb_typeof(args)='array' AND args->0 ? 'property' THEN
        prop := args->0->>'property';
        acc := env_full();
        IF prop IN ('datetime','end_datetime') THEN
            IF op IN ('in','like','ilike') THEN RETURN env_full(); END IF;   -- not a simple temporal bound
            IF op = 'between' THEN          r := tstzrange(cql2_ts(args->1), cql2_ts(args->2), '[]');
            ELSIF op IN ('<','<=','lt','lte') THEN r := tstzrange('-infinity', cql2_ts(args->1), '(]');
            ELSIF op IN ('>','>=','gt','gte') THEN r := tstzrange(cql2_ts(args->1), 'infinity', '[)');
            ELSE v := cql2_ts(args->1);     r := tstzrange(v, v, '[]'); END IF;
            IF prop = 'datetime' THEN acc.dt := tstzmultirange(r); ELSE acc.edt := tstzmultirange(r); END IF;
            RETURN acc;
        ELSIF prop = 'collection' THEN
            acc.colls := cql2_collection_set(op, args);          -- =/in/</>/between/like → collection set
            RETURN acc;
        ELSE
            RETURN env_full();                                   -- other property filters: no partition bound
        END IF;
    ELSE
        RETURN env_full();
    END IF;
END;
$$;

-- Full search envelope: top-level collections/datetime/bbox/intersects AND cql2(filter).
-- Collections are taken from the top-level `collections` arg AND from any `collection`
-- predicate anywhere in the cql2 tree (combined with the same AND/OR logic). `ids` do not
-- constrain partitions. If filter extraction fails, the top-level bounds still apply (the
-- filter part falls back to unconstrained) -- the envelope can only over-approximate;
-- correctness is enforced by each band query's WHERE.
-- search_to_cql2: normalize an entire STAC search into ONE CQL2 filter, so the WHERE
-- clause (cql2_query) and the partition-pruning envelope (cql2_envelope) are both
-- derived from a single representation -- no per-parameter parsing duplicated across
-- functions. Each top-level parameter maps to a CQL2 operator:
--   ids         -> in(id, [...])
--   collections -> in(collection, [...])
--   datetime    -> anyinteracts(datetime, <interval>)   (item interval overlaps query)
--   bbox/intersects -> s_intersects(geometry, <geojson>)
--   q           -> q(<terms>)                            (full-text)
--   query       -> query_to_cql2(...)                    (legacy)
--   filter      -> cql2 (cql-json translated to cql2-json)
-- All present parts are AND-ed. Returns NULL for an empty (match-all) search.
CREATE OR REPLACE FUNCTION search_to_cql2(j jsonb) RETURNS jsonb AS $$
DECLARE
    parts jsonb := '[]'::jsonb;
    fil jsonb;
    filterlang text;
    g geometry;
BEGIN
    IF j ? 'ids' THEN
        parts := parts || jsonb_build_object('op', 'in',
            'args', jsonb_build_array(jsonb_build_object('property', 'id'), j->'ids'));
    END IF;
    IF j ? 'collections' THEN
        parts := parts || jsonb_build_object('op', 'in',
            'args', jsonb_build_array(jsonb_build_object('property', 'collection'), j->'collections'));
    END IF;
    IF j ? 'datetime' THEN
        parts := parts || jsonb_build_object('op', 'anyinteracts',
            'args', jsonb_build_array(jsonb_build_object('property', 'datetime'), j->'datetime'));
    END IF;
    g := stac_geom(j);
    IF g IS NOT NULL THEN
        parts := parts || jsonb_build_object('op', 's_intersects',
            'args', jsonb_build_array(jsonb_build_object('property', 'geometry'), ST_AsGeoJSON(g)::jsonb));
    END IF;
    IF j ? 'q' THEN
        parts := parts || jsonb_build_object('op', 'q', 'args', j->'q');
    END IF;

    IF j ? 'query' AND j ? 'filter' THEN
        RAISE EXCEPTION 'Can only use either query or filter at one time.';
    END IF;
    IF j ? 'query' THEN
        fil := query_to_cql2(j->'query');
    ELSIF j ? 'filter' THEN
        filterlang := COALESCE(j->>'filter-lang', get_setting('default_filter_lang', j->'conf'));
        IF NOT (j->'filter') @? '$.**.op' OR filterlang = 'cql-json' THEN
            fil := cql1_to_cql2(j->'filter');
        ELSE
            fil := j->'filter';
        END IF;
    END IF;
    IF fil IS NOT NULL THEN
        parts := parts || fil;
    END IF;

    IF jsonb_array_length(parts) = 0 THEN
        RETURN NULL;
    ELSIF jsonb_array_length(parts) = 1 THEN
        RETURN parts->0;
    END IF;
    RETURN jsonb_build_object('op', 'and', 'args', parts);
END;
$$ LANGUAGE PLPGSQL STABLE;

-- The partition-pruning envelope is the envelope of the unified CQL2 filter. On any
-- extraction failure fall back to env_full() (scan all partitions) -- never a false
-- negative; exact correctness is always enforced by the WHERE clause.
CREATE OR REPLACE FUNCTION search_envelope(j jsonb) RETURNS pred_envelope LANGUAGE plpgsql STABLE AS $$
BEGIN
    RETURN cql2_envelope(search_to_cql2(j));
EXCEPTION WHEN others THEN
    RETURN env_full();
END;
$$;
-- END FRAGMENT: 002b_cql.sql

-- BEGIN FRAGMENT: 003a_items.sql
-- -----------------------------------------------------------------------
-- COLUMN LIST SYNC CONTRACT
-- When adding or removing promoted columns from the items table, ALL 6 of
-- these locations must be updated together:
--
--   1. items TABLE DDL (below)
--   2. content_dehydrate() — assigns each promoted column from props
--   3. promoted_item_property_defs() — metadata table mapping name→column
--   4. promoted_properties_from_item() — hydrates promoted columns back to jsonb
--   5. items_content_distinct_sql() — UPDATE-path / upsert DELETE content compare
--      (auto-derives promoted columns from promoted_items_column_list())
--   6. items_staging_dehydrate() — the single `enriched` SELECT that builds the
--      items rows for all three staging branches (insert / ignore / upsert)
--
-- Use promoted_items_column_list() to verify consistency at runtime.
-- The PGTap test 003_items.sql cross-references this against information_schema.
-- -----------------------------------------------------------------------

-- Item fragments: deduplicated part of item content (shared across items in a collection)
CREATE TABLE IF NOT EXISTS item_fragments (
    id bigserial PRIMARY KEY,
    collection text NOT NULL REFERENCES collections(id) ON DELETE CASCADE,
    -- Raw 32-byte sha256 of the fragment payload (see pgstac_hash_fragment).
    -- Stored as bytea, not 64-char hex text: half the size and a faster btree
    -- comparison on the (collection, hash) unique index. This hash is an
    -- internal dedup key only and is never exposed in the STAC API.
    hash bytea NOT NULL,
    content jsonb,
    links_template jsonb,
    created_at timestamptz NOT NULL DEFAULT now(),
    UNIQUE (collection, hash)
);
CREATE INDEX IF NOT EXISTS item_fragments_collection_idx ON item_fragments (collection);

CREATE TABLE items (
    id text NOT NULL,
    geometry geometry NOT NULL,
    collection text NOT NULL,
    datetime timestamptz NOT NULL,
    end_datetime timestamptz NOT NULL,
    datetime_is_range boolean NOT NULL DEFAULT false,
    stac_version text,
    stac_extensions jsonb DEFAULT '[]'::jsonb,
    pgstac_updated_at timestamptz NOT NULL DEFAULT now(),
    -- 32-byte sha256 of the canonical (RFC 8785-aligned) STAC item JSON set at
    -- ingest time. Allows external clients to detect unchanged items without a
    -- full fetch. Does NOT include the private column (operator metadata).
    item_hash bytea NOT NULL DEFAULT '\x'::bytea,
    -- Split columns. Keep fragment_id unmanaged by an FK
    -- because incremental NOT VALID FKs on partitioned items are not supported.
    fragment_id bigint,
    bbox jsonb,
    links jsonb,
    assets jsonb,
    properties jsonb,
    extra jsonb,
    -- Promoted queryable columns (redundant copies for index-only scans)
    created timestamptz,
    updated timestamptz,
    platform text,
    instruments text[],
    constellation text,
    mission text,
    eo_cloud_cover float8,
    bands jsonb,
    eo_snow_cover float8,
    gsd float8,
    proj_code text,
    proj_geometry jsonb,
    proj_wkt2 text,
    proj_projjson jsonb,
    proj_bbox jsonb,
    proj_centroid jsonb,
    proj_shape jsonb,
    proj_transform jsonb,
    sci_doi text,
    sci_citation text,
    sci_publications jsonb,
    view_off_nadir float8,
    view_incidence_angle float8,
    view_azimuth float8,
    view_sun_azimuth float8,
    view_sun_elevation float8,
    view_moon_azimuth float8,
    view_moon_elevation float8,
    file_size bigint,
    file_header_size bigint,
    file_checksum text,
    file_byte_order text,
    sat_orbit_state text,
    sat_relative_orbit integer,
    sat_absolute_orbit integer,
    sat_platform_international_designator text,
    sat_anx_datetime timestamptz,
    link_hrefs text[],
    -- Operator-private metadata: not returned by the STAC API, not included in
    -- item_hash, not part of the dehydrate/hydrate path. Set via direct UPDATE.
    private jsonb
)
PARTITION BY LIST (collection)
;

CREATE TABLE IF NOT EXISTS items_deleted_log (
    id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    item_id text NOT NULL,
    collection text NOT NULL,
    partition text,
    datetime timestamptz,
    end_datetime timestamptz,
    item_hash bytea NOT NULL DEFAULT '\x'::bytea,
    deleted_at timestamptz NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS items_deleted_log_deleted_at_idx ON items_deleted_log (deleted_at);

-- Field registry: tracks which JSON paths exist in each collection (for queryables)
CREATE TABLE IF NOT EXISTS item_field_registry (
    collection text NOT NULL REFERENCES collections(id) ON DELETE CASCADE,
    path text NOT NULL,
    is_leaf boolean DEFAULT true,
    value_kinds text[] DEFAULT '{}',
    first_seen timestamptz NOT NULL DEFAULT now(),
    last_seen timestamptz NOT NULL DEFAULT now(),
    PRIMARY KEY (collection, path)
);
CREATE INDEX IF NOT EXISTS item_field_registry_path_idx ON item_field_registry (path);

CREATE INDEX "datetime_idx" ON items USING BTREE (datetime DESC, end_datetime ASC);
CREATE INDEX "geometry_idx" ON items USING GIST (geometry);
CREATE INDEX IF NOT EXISTS items_fragment_id_idx ON items (fragment_id) WHERE fragment_id IS NOT NULL;

CREATE STATISTICS datetime_stats (dependencies) on datetime, end_datetime from items;

ALTER TABLE items ADD CONSTRAINT items_collections_fk FOREIGN KEY (collection) REFERENCES collections(id) ON DELETE CASCADE DEFERRABLE;

-- partition_after_triggerfunc: After-statement trigger on items.
-- Updates partition statistics for every partition touched by the current batch,
-- using run_or_queue() so the work is deferred rather than blocking the ingest
-- transaction.
CREATE OR REPLACE FUNCTION partition_after_triggerfunc() RETURNS TRIGGER AS $$
DECLARE
    p text;
    t timestamptz := clock_timestamp();
BEGIN
    RAISE NOTICE 'Updating partition stats %', t;
    FOR p IN SELECT DISTINCT partition
        FROM newdata n JOIN partition_sys_meta p
        ON (n.collection=p.collection AND n.datetime <@ p.partition_dtrange)
    LOOP
        PERFORM run_or_queue(format('SELECT update_partition_stats(%L, %L);', p, true));
    END LOOP;
    RAISE NOTICE 't: % %', t, clock_timestamp() - t;
    RETURN NULL;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

DROP TRIGGER IF EXISTS items_after_insert_trigger ON items;
CREATE TRIGGER items_after_insert_trigger
AFTER INSERT ON items
REFERENCING NEW TABLE AS newdata
FOR EACH STATEMENT
EXECUTE FUNCTION partition_after_triggerfunc();

DROP TRIGGER IF EXISTS items_after_update_trigger ON items;
CREATE TRIGGER items_after_update_trigger
AFTER UPDATE ON items
REFERENCING NEW TABLE AS newdata
FOR EACH STATEMENT
EXECUTE FUNCTION partition_after_triggerfunc();

DROP TRIGGER IF EXISTS items_after_delete_trigger ON items;
CREATE TRIGGER items_after_delete_trigger
AFTER DELETE ON items
REFERENCING OLD TABLE AS newdata
FOR EACH STATEMENT
EXECUTE FUNCTION partition_after_triggerfunc();

-- items_content_distinct_sql / items_content_changed: detect whether a direct
-- UPDATE actually changed the stored item content. Used by the touch trigger
-- (to refresh pgstac_updated_at) and by the upsert DELETE predicate, keeping
-- those two content comparisons in sync.
CREATE OR REPLACE FUNCTION items_content_distinct_sql(left_ref text, right_ref text)
RETURNS text AS $$
DECLARE
    clauses text[];
BEGIN
    clauses := ARRAY[
        format('%s.datetime_is_range IS DISTINCT FROM %s.datetime_is_range', left_ref, right_ref),
        format('%s.datetime IS DISTINCT FROM %s.datetime', left_ref, right_ref),
        format('%s.end_datetime IS DISTINCT FROM %s.end_datetime', left_ref, right_ref),
        format('%s.item_hash IS DISTINCT FROM %s.item_hash', left_ref, right_ref),
        format('%s.geometry IS DISTINCT FROM %s.geometry', left_ref, right_ref),
        format('%s.bbox IS DISTINCT FROM %s.bbox', left_ref, right_ref),
        format('%s.links IS DISTINCT FROM %s.links', left_ref, right_ref),
        format('%s.link_hrefs IS DISTINCT FROM %s.link_hrefs', left_ref, right_ref),
        format('%s.assets IS DISTINCT FROM %s.assets', left_ref, right_ref),
        format('%s.properties IS DISTINCT FROM %s.properties', left_ref, right_ref),
        format('%s.extra IS DISTINCT FROM %s.extra', left_ref, right_ref),
        format('%s.stac_version IS DISTINCT FROM %s.stac_version', left_ref, right_ref),
        format('%s.stac_extensions IS DISTINCT FROM %s.stac_extensions', left_ref, right_ref)
    ];

    clauses := clauses || ARRAY(
        SELECT format('%s.%I IS DISTINCT FROM %s.%I', left_ref, column_name, right_ref, column_name)
        FROM unnest(promoted_items_column_list()) AS column_name
    );

    RETURN array_to_string(clauses, E'\n                    OR ');
END;
$$ LANGUAGE PLPGSQL IMMUTABLE PARALLEL SAFE;

CREATE OR REPLACE FUNCTION items_content_changed(left_item items, right_item items)
RETURNS boolean AS $$
DECLARE
    changed boolean;
BEGIN
    EXECUTE format('SELECT %s', items_content_distinct_sql('($1)', '($2)'))
    INTO changed
    USING left_item, right_item;

    RETURN COALESCE(changed, FALSE);
END;
$$ LANGUAGE PLPGSQL IMMUTABLE PARALLEL SAFE;

-- items_touch_triggerfunc: refresh pgstac_updated_at when a direct UPDATE changes
-- the stored item content. It deliberately does NOT recompute item_hash:
-- item_hash is the canonical (RFC 8785-aligned) hash of the item *as ingested*
-- through create_item / upsert_item / update_item (set once in content_dehydrate),
-- so it stays externally reproducible by a client hashing its own copy.
-- A raw `UPDATE items SET ...` that bypasses the staging path leaves item_hash
-- referring to the last ingested document; re-ingest via upsert_item to refresh.
CREATE OR REPLACE FUNCTION items_touch_triggerfunc() RETURNS TRIGGER AS $$
BEGIN
    IF NOT items_content_changed(OLD, NEW) THEN
        RETURN NEW;
    END IF;

    NEW.pgstac_updated_at := now();
    RETURN NEW;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

DROP TRIGGER IF EXISTS items_before_upsert_trigger ON items;
DROP TRIGGER IF EXISTS items_before_update_trigger ON items;
CREATE TRIGGER items_before_update_trigger
BEFORE UPDATE ON items
FOR EACH ROW
EXECUTE FUNCTION items_touch_triggerfunc();

CREATE OR REPLACE FUNCTION items_delete_log_trigger() RETURNS TRIGGER AS $$
BEGIN
    INSERT INTO items_deleted_log (
        item_id,
        collection,
        partition,
        datetime,
        end_datetime,
        item_hash
    )
    SELECT
        old_rows.id,
        old_rows.collection,
        (partition_name(old_rows.collection, old_rows.datetime)).partition_name,
        old_rows.datetime,
        old_rows.end_datetime,
        old_rows.item_hash
    FROM old_rows;

    RETURN NULL;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION strip_promoted_properties(props jsonb) RETURNS jsonb AS $$
    SELECT COALESCE(props, '{}'::jsonb) - COALESCE(
        (SELECT array_agg(name ORDER BY name) FROM promoted_item_property_defs()),
        '{}'::text[]
    ) - ARRAY['datetime', 'start_datetime', 'end_datetime'];
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;

CREATE OR REPLACE FUNCTION tstz_to_stac_text(value timestamptz) RETURNS text AS $$
    SELECT CASE
        WHEN value IS NULL THEN NULL
        ELSE trim(trailing '.' FROM trim(trailing '0' FROM to_char(
            value AT TIME ZONE 'UTC',
            'YYYY-MM-DD"T"HH24:MI:SS.US'
        ))) || 'Z'
    END;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;

CREATE OR REPLACE FUNCTION temporal_properties_from_item(_item items) RETURNS jsonb AS $$
    SELECT CASE
        WHEN _item.datetime_is_range THEN jsonb_build_object('datetime', NULL)
            || jsonb_strip_nulls(jsonb_build_object(
                'start_datetime', tstz_to_stac_text(_item.datetime),
                'end_datetime', tstz_to_stac_text(_item.end_datetime)
            ))
        ELSE jsonb_build_object('datetime', tstz_to_stac_text(_item.datetime))
    END;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;

-- promoted_properties_from_item: Rehydrate the promoted scalar columns back into
-- a STAC properties object. This is the inverse of content_dehydrate's explicit
-- per-column extraction and is written in the same explicit style on purpose:
-- a direct jsonb_strip_nulls(jsonb_build_object(...)) is ~35% faster than routing
-- the column->STAC-name mapping through promoted_item_property_defs() with a
-- per-item join + jsonb_object_agg, and produces identical output (verified on
-- the PC fixtures + an all-fields synthetic item). Keep the property list in sync
-- with content_dehydrate and the items DDL (see the COLUMN LIST SYNC CONTRACT at
-- the top of this file).
CREATE OR REPLACE FUNCTION promoted_properties_from_item(_item items) RETURNS jsonb AS $$
    SELECT temporal_properties_from_item(_item) || jsonb_strip_nulls(jsonb_build_object(
        'created', CASE WHEN _item.created IS NULL THEN NULL ELSE tstz_to_stac_text(_item.created) END,
        'updated', CASE WHEN _item.updated IS NULL THEN NULL ELSE tstz_to_stac_text(_item.updated) END,
        'platform', _item.platform,
        'instruments', _item.instruments,
        'constellation', _item.constellation,
        'mission', _item.mission,
        'eo:cloud_cover', _item.eo_cloud_cover,
        'bands', _item.bands,
        'eo:snow_cover', _item.eo_snow_cover,
        'gsd', _item.gsd,
        'proj:code', _item.proj_code,
        'proj:geometry', _item.proj_geometry,
        'proj:wkt2', _item.proj_wkt2,
        'proj:projjson', _item.proj_projjson,
        'proj:bbox', _item.proj_bbox,
        'proj:centroid', _item.proj_centroid,
        'proj:shape', _item.proj_shape,
        'proj:transform', _item.proj_transform,
        'sci:doi', _item.sci_doi,
        'sci:citation', _item.sci_citation,
        'sci:publications', _item.sci_publications,
        'view:off_nadir', _item.view_off_nadir,
        'view:incidence_angle', _item.view_incidence_angle,
        'view:azimuth', _item.view_azimuth,
        'view:sun_azimuth', _item.view_sun_azimuth,
        'view:sun_elevation', _item.view_sun_elevation,
        'view:moon_azimuth', _item.view_moon_azimuth,
        'view:moon_elevation', _item.view_moon_elevation,
        'file:size', _item.file_size,
        'file:header_size', _item.file_header_size,
        'file:checksum', _item.file_checksum,
        'file:byte_order', _item.file_byte_order,
        'sat:orbit_state', _item.sat_orbit_state,
        'sat:relative_orbit', _item.sat_relative_orbit,
        'sat:absolute_orbit', _item.sat_absolute_orbit,
        'sat:platform_international_designator', _item.sat_platform_international_designator,
        'sat:anx_datetime', CASE WHEN _item.sat_anx_datetime IS NULL THEN NULL ELSE tstz_to_stac_text(_item.sat_anx_datetime) END
    ));
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;

DROP TRIGGER IF EXISTS items_delete_log_after_delete_trigger ON items;
CREATE TRIGGER items_delete_log_after_delete_trigger
    AFTER DELETE ON items
    REFERENCING OLD TABLE AS old_rows
    FOR EACH STATEMENT EXECUTE FUNCTION items_delete_log_trigger();




CREATE OR REPLACE FUNCTION stac_links_strip_hrefs(links jsonb) RETURNS jsonb AS $$
    SELECT CASE
        WHEN links IS NULL OR jsonb_typeof(links) <> 'array' OR jsonb_array_length(links) = 0 THEN NULL
        ELSE
            (
                SELECT jsonb_agg(
                    CASE
                        WHEN jsonb_typeof(link) = 'object' THEN link - 'href'
                        ELSE link
                    END
                    ORDER BY ord
                )
                FROM jsonb_array_elements(links) WITH ORDINALITY AS elements(link, ord)
            )
    END;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;

CREATE OR REPLACE FUNCTION stac_links_href_array(links jsonb) RETURNS text[] AS $$
    SELECT CASE
        WHEN links IS NULL OR jsonb_typeof(links) <> 'array' OR jsonb_array_length(links) = 0 THEN NULL
        ELSE ARRAY(
            SELECT link->>'href'
            FROM jsonb_array_elements(links) WITH ORDINALITY AS elements(link, ord)
            ORDER BY ord
        )
    END;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;

CREATE OR REPLACE FUNCTION stac_links_hydrate(
    links_template jsonb,
    link_hrefs text[]
) RETURNS jsonb AS $$
    SELECT CASE
        WHEN links_template IS NULL OR jsonb_typeof(links_template) <> 'array' THEN '[]'::jsonb
        WHEN link_hrefs IS NULL OR array_length(link_hrefs, 1) IS NULL THEN
            COALESCE(
                (SELECT jsonb_agg(link ORDER BY ord)
                 FROM jsonb_array_elements(links_template) WITH ORDINALITY AS elements(link, ord)),
                '[]'::jsonb
            )
        ELSE COALESCE(
            (
                SELECT jsonb_agg(
                    CASE
                        WHEN jsonb_typeof(link) = 'object' AND hrefs.href IS NOT NULL THEN
                            jsonb_set(link - 'href', '{href}', to_jsonb(hrefs.href), true)
                        WHEN jsonb_typeof(link) = 'object' THEN link - 'href'
                        ELSE link
                    END
                    ORDER BY ord
                )
                FROM jsonb_array_elements(links_template) WITH ORDINALITY AS elements(link, ord)
                LEFT JOIN LATERAL (
                    SELECT link_hrefs[ord] AS href
                ) AS hrefs ON TRUE
            ),
            '[]'::jsonb
        )
    END;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;


CREATE OR REPLACE FUNCTION content_dehydrate(content jsonb) RETURNS items AS $$
    SELECT
        content->>'id' AS id,
        stac_geom(content) AS geometry,
        content->>'collection' AS collection,
        stac_datetime(content) AS datetime,
        stac_end_datetime(content) AS end_datetime,
        CASE
            WHEN (content->'properties')->'datetime' IS NOT NULL AND (content->'properties')->'datetime' <> 'null'::jsonb THEN FALSE
            ELSE (
                ((content->'properties')->'start_datetime' IS NOT NULL AND (content->'properties')->'start_datetime' <> 'null'::jsonb)
                OR ((content->'properties')->'end_datetime' IS NOT NULL AND (content->'properties')->'end_datetime' <> 'null'::jsonb)
            )
        END AS datetime_is_range,
        content->>'stac_version' AS stac_version,
        COALESCE(content->'stac_extensions', '[]'::jsonb) AS stac_extensions,
        now() AS pgstac_updated_at,
        pgstac.jsonb_hash(content) AS item_hash,
        NULL::bigint AS fragment_id,
        content->'bbox' AS bbox,
        CASE WHEN content->'links' IS NOT NULL AND content->'links' <> '[]'::jsonb THEN content->'links' END AS links,
        CASE WHEN content->'assets' IS NOT NULL AND content->'assets' <> '{}'::jsonb THEN content->'assets' END AS assets,
        strip_promoted_properties(content->'properties') AS properties,
        content - '{id,geometry,collection,type,bbox,links,assets,properties,stac_version,stac_extensions}'::text[] AS extra,

        ((content->'properties')->>'created')::timestamptz AS created,
        ((content->'properties')->>'updated')::timestamptz AS updated,
        ((content->'properties')->>'platform') AS platform,
        to_text_array((content->'properties')->'instruments') AS instruments,
        ((content->'properties')->>'constellation') AS constellation,
        ((content->'properties')->>'mission') AS mission,
        ((content->'properties')->>'eo:cloud_cover')::float8 AS eo_cloud_cover,
        ((content->'properties')->'bands') AS bands,
        ((content->'properties')->>'eo:snow_cover')::float8 AS eo_snow_cover,
        ((content->'properties')->>'gsd')::float8 AS gsd,

        ((content->'properties')->>'proj:code') AS proj_code,
        ((content->'properties')->'proj:geometry') AS proj_geometry,
        ((content->'properties')->>'proj:wkt2') AS proj_wkt2,
        ((content->'properties')->'proj:projjson') AS proj_projjson,
        ((content->'properties')->'proj:bbox') AS proj_bbox,
        ((content->'properties')->'proj:centroid') AS proj_centroid,
        ((content->'properties')->'proj:shape') AS proj_shape,
        ((content->'properties')->'proj:transform') AS proj_transform,

        ((content->'properties')->>'sci:doi') AS sci_doi,
        ((content->'properties')->>'sci:citation') AS sci_citation,
        ((content->'properties')->'sci:publications') AS sci_publications,

        ((content->'properties')->>'view:off_nadir')::float8 AS view_off_nadir,
        ((content->'properties')->>'view:incidence_angle')::float8 AS view_incidence_angle,
        ((content->'properties')->>'view:azimuth')::float8 AS view_azimuth,
        ((content->'properties')->>'view:sun_azimuth')::float8 AS view_sun_azimuth,
        ((content->'properties')->>'view:sun_elevation')::float8 AS view_sun_elevation,
        ((content->'properties')->>'view:moon_azimuth')::float8 AS view_moon_azimuth,
        ((content->'properties')->>'view:moon_elevation')::float8 AS view_moon_elevation,

        ((content->'properties')->>'file:size')::bigint AS file_size,
        ((content->'properties')->>'file:header_size')::bigint AS file_header_size,
        ((content->'properties')->>'file:checksum') AS file_checksum,
        ((content->'properties')->>'file:byte_order') AS file_byte_order,

        ((content->'properties')->>'sat:orbit_state') AS sat_orbit_state,
        ((content->'properties')->>'sat:relative_orbit')::integer AS sat_relative_orbit,
        ((content->'properties')->>'sat:absolute_orbit')::integer AS sat_absolute_orbit,
        ((content->'properties')->>'sat:platform_international_designator') AS sat_platform_international_designator,
        ((content->'properties')->>'sat:anx_datetime')::timestamptz AS sat_anx_datetime,
        stac_links_href_array(content->'links') AS link_hrefs,
        -- private is operator-managed metadata outside the STAC item; always NULL from ingest
        NULL::jsonb AS private;
$$ LANGUAGE SQL STABLE;

CREATE OR REPLACE FUNCTION include_field(f text, fields jsonb DEFAULT '{}'::jsonb) RETURNS boolean AS $$
DECLARE
    includes jsonb := fields->'include';
    excludes jsonb := fields->'exclude';
BEGIN
    IF f IS NULL THEN
        RETURN NULL;
    END IF;


    IF
        jsonb_typeof(excludes) = 'array'
        AND jsonb_array_length(excludes)>0
        AND excludes ? f
    THEN
        RETURN FALSE;
    END IF;

    IF
        (
            jsonb_typeof(includes) = 'array'
            AND jsonb_array_length(includes) > 0
            AND includes ? f
        ) OR
        (
            includes IS NULL
            OR jsonb_typeof(includes) = 'null'
            OR jsonb_array_length(includes) = 0
        )
    THEN
        RETURN TRUE;
    END IF;

    RETURN FALSE;
END;
$$ LANGUAGE PLPGSQL IMMUTABLE;

-- content_hydrate: Reassemble a full STAC item JSON from the split columns
-- and the shared fragment content.
--
-- Two overloads:
--   content_hydrate(_item, fields)                    -- looks up fragment via subquery
--   content_hydrate(_item, _fragment, fields)         -- uses pre-joined fragment (streaming path)
--
-- The 3-arg form is the real implementation; the 2-arg form is a thin wrapper.
-- Use the 3-arg form when the fragment is already available from a LEFT JOIN
-- (e.g. in search_sql) to avoid a per-row correlated subquery.

-- content_hydrate: reassemble a full STAC item from its split-storage row and shared
-- fragment. The fragment is optional: pass it (e.g. from a LEFT JOIN in the streaming
-- path) to avoid a per-row lookup, or omit it and content_hydrate fetches it when the
-- item has a fragment_id. One function via a defaulted trailing arg (no 2-arg overload).
CREATE OR REPLACE FUNCTION content_hydrate(
    _item items,
    fields jsonb DEFAULT '{}'::jsonb,
    _fragment item_fragments DEFAULT NULL
) RETURNS jsonb AS $$
DECLARE
    geom jsonb;
    output jsonb;
    frag_content jsonb;
    frag_links_template jsonb;
    merged_assets jsonb;
    merged_properties jsonb;
    hydrated_stac_version text;
    hydrated_stac_extensions jsonb;
    hydrated_links jsonb;
BEGIN
    -- fetch the fragment if it was not supplied and the item has one.
    IF _fragment IS NULL AND _item.fragment_id IS NOT NULL THEN
        SELECT * INTO _fragment FROM item_fragments WHERE id = _item.fragment_id;
    END IF;

    IF include_field('geometry', fields) THEN
        geom := ST_ASGeoJson(_item.geometry, 20)::jsonb;
    END IF;

    -- _fragment comes from a LEFT JOIN; its id is NULL when the item has no fragment.
    IF _fragment.id IS NOT NULL THEN
        frag_content        := _fragment.content;
        frag_links_template := _fragment.links_template;
    END IF;

    -- Merge: fragment provides shared asset/property values; per-item provides individual values.
    merged_assets     := jsonb_merge_recursive(frag_content->'assets', COALESCE(_item.assets, '{}'::jsonb));
    merged_properties := jsonb_merge_recursive(frag_content->'properties', COALESCE(_item.properties, '{}'::jsonb));
    merged_properties := promoted_properties_from_item(_item) || COALESCE(merged_properties, '{}'::jsonb);
    hydrated_stac_version := COALESCE(_item.stac_version, frag_content->>'stac_version');
    hydrated_stac_extensions := CASE
        WHEN _item.stac_extensions IS NOT NULL AND _item.stac_extensions <> '[]'::jsonb THEN _item.stac_extensions
        ELSE COALESCE(frag_content->'stac_extensions', _item.stac_extensions)
    END;
    IF _fragment.id IS NOT NULL THEN
        hydrated_links := stac_links_hydrate(frag_links_template, _item.link_hrefs);
    ELSE
        hydrated_links := COALESCE(_item.links, '[]'::jsonb);
    END IF;

    output := jsonb_build_object(
        'id',         _item.id,
        'geometry',   geom,
        'collection', _item.collection,
        'type',       'Feature'
    );
    IF _item.bbox IS NOT NULL THEN
        output := output || jsonb_build_object('bbox', _item.bbox);
    END IF;
    IF hydrated_stac_version IS NOT NULL THEN
        output := output || jsonb_build_object('stac_version', hydrated_stac_version);
    END IF;
    IF hydrated_stac_extensions IS NOT NULL AND hydrated_stac_extensions <> '[]'::jsonb THEN
        output := output || jsonb_build_object('stac_extensions', hydrated_stac_extensions);
    END IF;
    IF hydrated_links IS NOT NULL THEN
        output := output || jsonb_build_object('links', hydrated_links);
    END IF;
    IF merged_assets != '{}'::jsonb THEN
        output := output || jsonb_build_object('assets', merged_assets);
    END IF;
    IF merged_properties IS NOT NULL THEN
        output := output || jsonb_build_object('properties', merged_properties);
    END IF;
    IF _item.extra IS NOT NULL THEN
        output := output || _item.extra;
    END IF;

    RETURN jsonb_fields(output, fields);
END;
$$ LANGUAGE PLPGSQL STABLE PARALLEL SAFE;


CREATE UNLOGGED TABLE items_staging (
    content JSONB NOT NULL
);
CREATE UNLOGGED TABLE items_staging_ignore (
    content JSONB NOT NULL
);
CREATE UNLOGGED TABLE items_staging_upsert (
    content JSONB NOT NULL
);
-- Upsert staging that does NOT walk the field registry. This is the RDS-safe way to
-- signal "skip the registry walk" (a session GUC like pgstac.skip_field_registry can't
-- be relied on under RDS): a loader that already computed the paths calls
-- register_field_paths() and then loads here, avoiding the walk-twice cost.
CREATE UNLOGGED TABLE items_staging_noregistry (
    content JSONB NOT NULL
);

-- items_staging_dehydrate: Shared ingest pipeline for all three staging tables.
-- Given the batch of raw STAC item JSONs it dehydrates each into items columns,
-- computes and deduplicates the per-collection fragment payload (inserting new
-- item_fragments rows via ON CONFLICT), assigns fragment_id, and strips
-- fragment-covered keys. Returns the fully-enriched rows as the items rowtype so
-- each staging trigger branch is a single INSERT differing only in conflict
-- policy. The enriched column list lives here once (previously duplicated 3x).
CREATE OR REPLACE FUNCTION items_staging_dehydrate(_contents jsonb[]) RETURNS SETOF items AS $$
        WITH raw AS MATERIALIZED (
            SELECT
                n.content AS orig_content,
                d.*
            FROM unnest(_contents) AS n(content)
            CROSS JOIN LATERAL content_dehydrate(n.content) d
        ),
        fragmented_base AS MATERIALIZED (
            SELECT
                r.*,
                c.fragment_config,
                stac_links_strip_hrefs(r.orig_content->'links') AS links_template,
                extract_fragment(r.orig_content, c.fragment_config) AS frag_content
            FROM raw r
            JOIN collections c ON c.id = r.collection
        ),
        fragmented AS MATERIALIZED (
            SELECT
                fb.*,
                CASE
                    WHEN fb.frag_content IS NULL
                        AND fb.links_template IS NULL THEN NULL
                    ELSE pgstac_hash_fragment(
                        jsonb_strip_nulls(
                            jsonb_build_object(
                                'content', NULLIF(fb.frag_content, '{}'::jsonb),
                                'links_template', fb.links_template
                            )
                        )
                    )
                END AS frag_hash
            FROM fragmented_base fb
        ),
        fragments AS MATERIALIZED (
            SELECT DISTINCT ON (collection, frag_hash)
                collection,
                frag_hash,
                frag_content,
                fragment_config,
                links_template
            FROM fragmented
            WHERE frag_hash IS NOT NULL
            ORDER BY collection, frag_hash
        ),
        insert_fragments AS (
            INSERT INTO item_fragments (collection, hash, content, links_template)
            SELECT collection, frag_hash, COALESCE(frag_content, '{}'::jsonb), links_template
            FROM fragments
            ON CONFLICT (collection, hash) DO NOTHING
            RETURNING id, collection, hash
        ),
        all_fragments AS (
            SELECT id, collection, hash FROM insert_fragments
            UNION ALL
            SELECT f.id, f.collection, f.hash
            FROM item_fragments f
            JOIN fragments p ON f.collection = p.collection AND f.hash = p.frag_hash
        ),
        enriched AS MATERIALIZED (
            SELECT
                r.id,
                r.geometry,
                r.collection,
                r.datetime,
                r.end_datetime,
                r.datetime_is_range,
                CASE
                    WHEN fragment_path_text(ARRAY['stac_version']) = ANY(f.fragment_config) THEN NULL
                    ELSE r.stac_version
                END AS stac_version,
                CASE
                    WHEN fragment_path_text(ARRAY['stac_extensions']) = ANY(f.fragment_config) THEN '[]'::jsonb
                    ELSE r.stac_extensions
                END AS stac_extensions,
                r.pgstac_updated_at,
                r.item_hash,
                af.id AS fragment_id,
                r.bbox,
                CASE
                    WHEN r.link_hrefs IS NOT NULL AND array_length(r.link_hrefs, 1) > 0 THEN NULL
                    ELSE r.links
                END AS links,
                strip_fragment_col(COALESCE(r.assets, '{}'::jsonb), 'assets', f.fragment_config) AS assets,
                strip_fragment_col(COALESCE(r.properties, '{}'::jsonb), 'properties', f.fragment_config) AS properties,
                r.extra,
                r.created,
                r.updated,
                r.platform,
                r.instruments,
                r.constellation,
                r.mission,
                r.eo_cloud_cover,
                r.bands,
                r.eo_snow_cover,
                r.gsd,
                r.proj_code,
                r.proj_geometry,
                r.proj_wkt2,
                r.proj_projjson,
                r.proj_bbox,
                r.proj_centroid,
                r.proj_shape,
                r.proj_transform,
                r.sci_doi,
                r.sci_citation,
                r.sci_publications,
                r.view_off_nadir,
                r.view_incidence_angle,
                r.view_azimuth,
                r.view_sun_azimuth,
                r.view_sun_elevation,
                r.view_moon_azimuth,
                r.view_moon_elevation,
                r.file_size,
                r.file_header_size,
                r.file_checksum,
                r.file_byte_order,
                r.sat_orbit_state,
                r.sat_relative_orbit,
                r.sat_absolute_orbit,
                r.sat_platform_international_designator,
                r.sat_anx_datetime,
                r.link_hrefs,
                NULL::jsonb AS private
            FROM fragmented r
            LEFT JOIN fragments f ON f.collection = r.collection AND f.frag_hash = r.frag_hash
            LEFT JOIN all_fragments af ON af.collection = f.collection AND af.hash = f.frag_hash
        )
    SELECT * FROM enriched;
$$ LANGUAGE SQL;

-- items_staging_triggerfunc: AFTER INSERT trigger on items_staging /
-- items_staging_ignore / items_staging_upsert. Ensures partitions exist, then
-- runs the shared items_staging_dehydrate() pipeline with the per-table conflict
-- policy (and, for upsert, a pre-DELETE of rows whose stored content changed),
-- and finally clears the staging table.
CREATE OR REPLACE FUNCTION items_staging_triggerfunc() RETURNS TRIGGER AS $$
DECLARE
    part text;
    ts timestamptz := clock_timestamp();
    nrows int;
    batch jsonb[];
BEGIN
    RAISE NOTICE 'Creating Partitions. %', clock_timestamp() - ts;

    FOR part IN WITH t AS (
        SELECT
            n.content->>'collection' as collection,
            stac_daterange(n.content->'properties') as dtr,
            partition_trunc
        FROM newdata n JOIN collections ON (n.content->>'collection'=collections.id)
    ), p AS (
        SELECT
            collection,
            COALESCE(date_trunc(partition_trunc::text, lower(dtr)),'-infinity') as d,
            tstzrange(min(lower(dtr)),max(lower(dtr)),'[]') as dtrange,
            tstzrange(min(upper(dtr)),max(upper(dtr)),'[]') as edtrange
        FROM t
        GROUP BY 1,2
    ) SELECT check_partition(collection, dtrange, edtrange) FROM p LOOP
        RAISE NOTICE 'Partition %', part;
    END LOOP;

    batch := ARRAY(SELECT content FROM newdata);

    RAISE NOTICE 'Doing the insert. %', clock_timestamp() - ts;
    IF TG_TABLE_NAME = 'items_staging' THEN
        INSERT INTO items SELECT * FROM items_staging_dehydrate(batch);
        GET DIAGNOSTICS nrows = ROW_COUNT;
        RAISE NOTICE 'Inserted % rows to items. %', nrows, clock_timestamp() - ts;
    ELSIF TG_TABLE_NAME = 'items_staging_ignore' THEN
        INSERT INTO items SELECT * FROM items_staging_dehydrate(batch)
        ON CONFLICT DO NOTHING;
        GET DIAGNOSTICS nrows = ROW_COUNT;
        RAISE NOTICE 'Inserted % rows to items. %', nrows, clock_timestamp() - ts;
    ELSIF TG_TABLE_NAME IN ('items_staging_upsert', 'items_staging_noregistry') THEN
        -- Delete existing rows whose stored content actually changed, then insert.
        EXECUTE format(
            $sql$
            DELETE FROM items i USING (
                SELECT d.*
                FROM newdata s
                CROSS JOIN LATERAL content_dehydrate(s.content) d
            ) s
            WHERE
                i.id = s.id
                AND i.collection = s.collection
                AND (
                    %s
                )
            $sql$,
            items_content_distinct_sql('i', 's')
        );
        GET DIAGNOSTICS nrows = ROW_COUNT;
        RAISE NOTICE 'Deleted % rows from items. %', nrows, clock_timestamp() - ts;
        INSERT INTO items SELECT * FROM items_staging_dehydrate(batch)
        ON CONFLICT DO NOTHING;
        GET DIAGNOSTICS nrows = ROW_COUNT;
        RAISE NOTICE 'Inserted % rows to items. %', nrows, clock_timestamp() - ts;
    END IF;

    -- Exhaustive field registry (append-only), statement-level + set-based over the
    -- whole batch's RAW contents (original STAC paths, not the dehydrated columns),
    -- grouped by collection. Skipped when loading via items_staging_noregistry (the
    -- RDS-safe signal) or when `pgstac.skip_field_registry = true` (where GUCs are
    -- available), so a loader that already computed the paths (e.g. the Rust client)
    -- does not do the work twice — it calls register_field_paths() directly instead.
    IF TG_TABLE_NAME <> 'items_staging_noregistry'
       AND NOT coalesce(current_setting('pgstac.skip_field_registry', true)::boolean, false) THEN
        INSERT INTO item_field_registry (collection, path, is_leaf, value_kinds, first_seen, last_seen)
        SELECT
            n.content->>'collection',
            r.path,
            bool_and(r.is_leaf),
            array_agg(DISTINCT r.value_kind) FILTER (WHERE r.value_kind IS NOT NULL),
            now(), now()
        FROM unnest(batch) AS n(content)
        -- only register collections that exist (items for unknown collections are
        -- dropped by the dehydrate, and the registry FK would otherwise abort here).
        JOIN collections col ON col.id = n.content->>'collection'
        CROSS JOIN LATERAL jsonb_field_rows(n.content) AS r(path, is_leaf, value_kind)
        GROUP BY n.content->>'collection', r.path
        ON CONFLICT (collection, path) DO UPDATE SET
            is_leaf     = EXCLUDED.is_leaf,
            value_kinds = (SELECT array_agg(DISTINCT v)
                           FROM unnest(item_field_registry.value_kinds || EXCLUDED.value_kinds) t(v)),
            last_seen   = now();
        RAISE NOTICE 'Updated field registry. %', clock_timestamp() - ts;
    END IF;

    RAISE NOTICE 'Deleting data from staging table. %', clock_timestamp() - ts;
    EXECUTE format('DELETE FROM %I', TG_TABLE_NAME);
    RAISE NOTICE 'Done. %', clock_timestamp() - ts;

    RETURN NULL;
END;
$$ LANGUAGE PLPGSQL;


DROP TRIGGER IF EXISTS items_staging_insert_trigger ON items_staging;
CREATE TRIGGER items_staging_insert_trigger AFTER INSERT ON items_staging REFERENCING NEW TABLE AS newdata
    FOR EACH STATEMENT EXECUTE PROCEDURE items_staging_triggerfunc();

DROP TRIGGER IF EXISTS items_staging_insert_ignore_trigger ON items_staging_ignore;
CREATE TRIGGER items_staging_insert_ignore_trigger AFTER INSERT ON items_staging_ignore REFERENCING NEW TABLE AS newdata
    FOR EACH STATEMENT EXECUTE PROCEDURE items_staging_triggerfunc();

DROP TRIGGER IF EXISTS items_staging_insert_upsert_trigger ON items_staging_upsert;
CREATE TRIGGER items_staging_insert_upsert_trigger AFTER INSERT ON items_staging_upsert REFERENCING NEW TABLE AS newdata
    FOR EACH STATEMENT EXECUTE PROCEDURE items_staging_triggerfunc();

DROP TRIGGER IF EXISTS items_staging_insert_noregistry_trigger ON items_staging_noregistry;
CREATE TRIGGER items_staging_insert_noregistry_trigger AFTER INSERT ON items_staging_noregistry REFERENCING NEW TABLE AS newdata
    FOR EACH STATEMENT EXECUTE PROCEDURE items_staging_triggerfunc();


CREATE OR REPLACE FUNCTION item_by_id(_id text, _collection text DEFAULT NULL) RETURNS items AS
$$
DECLARE
    i items%ROWTYPE;
BEGIN
    SELECT * INTO i FROM items WHERE id=_id AND (_collection IS NULL OR collection=_collection) LIMIT 1;
    RETURN i;
END;
$$ LANGUAGE PLPGSQL STABLE SET SEARCH_PATH TO pgstac, public;

CREATE OR REPLACE FUNCTION get_item(_id text, _collection text DEFAULT NULL) RETURNS jsonb AS $$
    SELECT content_hydrate(items) FROM items WHERE id=_id AND (_collection IS NULL OR collection=_collection);
$$ LANGUAGE SQL STABLE SET SEARCH_PATH TO pgstac, public;

CREATE OR REPLACE FUNCTION delete_item(_id text, _collection text DEFAULT NULL) RETURNS VOID AS $$
DECLARE
out items%ROWTYPE;
BEGIN
    DELETE FROM items WHERE id = _id AND (_collection IS NULL OR collection=_collection) RETURNING * INTO STRICT out;
END;
$$ LANGUAGE PLPGSQL;

--/*
CREATE OR REPLACE FUNCTION create_item(data jsonb) RETURNS VOID AS $$
    INSERT INTO items_staging (content) VALUES (data);
$$ LANGUAGE SQL SET SEARCH_PATH TO pgstac,public;


CREATE OR REPLACE FUNCTION update_item(content jsonb) RETURNS VOID AS $$
DECLARE
    old items %ROWTYPE;
    out items%ROWTYPE;
BEGIN
    PERFORM delete_item(content->>'id', content->>'collection');
    PERFORM create_item(content);
END;
$$ LANGUAGE PLPGSQL SET SEARCH_PATH TO pgstac,public;

CREATE OR REPLACE FUNCTION upsert_item(data jsonb) RETURNS VOID AS $$
    INSERT INTO items_staging_upsert (content) VALUES (data);
$$ LANGUAGE SQL SET SEARCH_PATH TO pgstac,public;

CREATE OR REPLACE FUNCTION create_items(data jsonb) RETURNS VOID AS $$
    INSERT INTO items_staging (content)
    SELECT * FROM jsonb_array_elements(data);
$$ LANGUAGE SQL SET SEARCH_PATH TO pgstac,public;

CREATE OR REPLACE FUNCTION upsert_items(data jsonb) RETURNS VOID AS $$
    INSERT INTO items_staging_upsert (content)
    SELECT * FROM jsonb_array_elements(data);
$$ LANGUAGE SQL SET SEARCH_PATH TO pgstac,public;


CREATE OR REPLACE FUNCTION collection_bbox(id text) RETURNS jsonb AS $$
    SELECT (replace(replace(replace(st_extent(geometry)::text,'BOX(','[['),')',']]'),' ',','))::jsonb
    FROM items WHERE collection=$1;
    ;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE SET SEARCH_PATH TO pgstac, public;

CREATE OR REPLACE FUNCTION collection_temporal_extent(id text) RETURNS jsonb AS $$
    SELECT to_jsonb(array[array[min(datetime), max(datetime)]])
    FROM items WHERE collection=$1;
;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE SET SEARCH_PATH TO pgstac, public;

CREATE OR REPLACE FUNCTION update_collection_extents() RETURNS VOID AS $$
UPDATE collections
    SET content = jsonb_set_lax(
        content,
        '{extent}'::text[],
        collection_extent(id, FALSE),
        true,
        'use_json_null'
    )
;
$$ LANGUAGE SQL;

-- ---------------------------------------------------------------------------
-- Field Registry: walks JSONB item content to track which paths exist in each
-- collection.  Used to auto-populate queryables and support schema inference.
-- jsonb_field_rows is defined in 001a_jsonutils.sql (loaded first).
-- ---------------------------------------------------------------------------

-- update_field_registry_from_sample: UPSERT registry rows from a pre-selected array of
-- raw item content JSONBs.  Callers supply the sample to decouple sampling strategy
-- from the registry write; merge value_kinds to accumulate observed types over time.
CREATE OR REPLACE FUNCTION update_field_registry_from_sample(
    _collection text,
    item_contents jsonb[]
) RETURNS void AS $$
    INSERT INTO item_field_registry (collection, path, is_leaf, value_kinds, first_seen, last_seen)
    SELECT
        _collection,
        r.path,
        bool_and(r.is_leaf)                                                       AS is_leaf,
        array_agg(DISTINCT r.value_kind) FILTER (WHERE r.value_kind IS NOT NULL)  AS value_kinds,
        now(),
        now()
    FROM unnest(item_contents) AS item(content)
    CROSS JOIN LATERAL jsonb_field_rows(item.content) AS r(path, is_leaf, value_kind)
    GROUP BY r.path
    ON CONFLICT (collection, path) DO UPDATE SET
        is_leaf     = EXCLUDED.is_leaf,
        value_kinds = (
            SELECT array_agg(DISTINCT v)
            FROM unnest(item_field_registry.value_kinds || EXCLUDED.value_kinds) t(v)
        ),
        last_seen   = now()
    ;
$$ LANGUAGE SQL VOLATILE;

-- update_field_registry_from_items: Sample a live collection and UPSERT registry rows.
-- Uses TABLESAMPLE BERNOULLI(5) for large collections (>10k rows by pg_class estimate)
-- and LIMIT 1000 for smaller ones to avoid a full seq-scan for tiny collections.
-- pg_class.reltuples is an estimate (may be stale); its only role is threshold selection.
-- Returns (registered_paths, rows_processed) for observability.
CREATE OR REPLACE FUNCTION update_field_registry_from_items(
    _collection text
) RETURNS TABLE (registered_paths int, rows_processed int) AS $$
DECLARE
    est_rows bigint;
    nrows    int;
    npaths   int;
BEGIN
    -- Sum reltuples across the registered item partitions for this collection.
    -- reltuples can be -1 (never analyzed); treat negative values as zero.
    SELECT COALESCE(sum(GREATEST(c.reltuples::bigint, 0)), 0) INTO est_rows
    FROM partitions_view p
    JOIN pg_class c ON c.relname = p.partition
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE p.collection = _collection
      AND n.nspname = 'pgstac'
      AND c.relkind = 'r';

    IF est_rows > 10000 THEN
        -- Large collection: use statistical sampling to avoid full seq-scan.
        WITH sampled AS (
            SELECT content_hydrate(i) AS content FROM items i TABLESAMPLE BERNOULLI(5) WHERE i.collection = _collection
        ),
        upserted AS (
            INSERT INTO item_field_registry (collection, path, is_leaf, value_kinds, first_seen, last_seen)
            SELECT
                _collection,
                r.path,
                bool_and(r.is_leaf)                                                       AS is_leaf,
                array_agg(DISTINCT r.value_kind) FILTER (WHERE r.value_kind IS NOT NULL)  AS value_kinds,
                now(), now()
            FROM sampled
            CROSS JOIN LATERAL jsonb_field_rows(content) AS r(path, is_leaf, value_kind)
            GROUP BY r.path
            ON CONFLICT (collection, path) DO UPDATE SET
                is_leaf     = EXCLUDED.is_leaf,
                value_kinds = (
                    SELECT array_agg(DISTINCT v)
                    FROM unnest(item_field_registry.value_kinds || EXCLUDED.value_kinds) t(v)
                ),
                last_seen   = now()
            RETURNING 1
        )
        SELECT
            (SELECT count(*)::int FROM upserted),
            (SELECT count(*)::int FROM sampled)
        INTO npaths, nrows;
    ELSE
        -- Small collection: process up to 1000 rows to avoid BERNOULLI returning 0 rows.
        WITH sampled AS (
            SELECT content_hydrate(i) AS content FROM items i WHERE i.collection = _collection LIMIT 1000
        ),
        upserted AS (
            INSERT INTO item_field_registry (collection, path, is_leaf, value_kinds, first_seen, last_seen)
            SELECT
                _collection,
                r.path,
                bool_and(r.is_leaf)                                                       AS is_leaf,
                array_agg(DISTINCT r.value_kind) FILTER (WHERE r.value_kind IS NOT NULL)  AS value_kinds,
                now(), now()
            FROM sampled
            CROSS JOIN LATERAL jsonb_field_rows(content) AS r(path, is_leaf, value_kind)
            GROUP BY r.path
            ON CONFLICT (collection, path) DO UPDATE SET
                is_leaf     = EXCLUDED.is_leaf,
                value_kinds = (
                    SELECT array_agg(DISTINCT v)
                    FROM unnest(item_field_registry.value_kinds || EXCLUDED.value_kinds) t(v)
                ),
                last_seen   = now()
            RETURNING 1
        )
        SELECT
            (SELECT count(*)::int FROM upserted),
            (SELECT count(*)::int FROM sampled)
        INTO npaths, nrows;
    END IF;

    RETURN QUERY SELECT npaths, nrows;
END;
$$ LANGUAGE PLPGSQL VOLATILE SECURITY DEFINER;

-- refresh_field_registry: Expire stale registry entries that haven't been seen recently.
-- Intended for scheduled maintenance (e.g. pg_cron daily job).
-- Returns (collection, expired_paths) for each collection affected.
CREATE OR REPLACE FUNCTION refresh_field_registry(
    _collection text DEFAULT NULL,
    retention_interval interval DEFAULT '90 days'
) RETURNS TABLE (collection_id text, expired_paths int) AS $$
    WITH deleted AS (
        DELETE FROM item_field_registry
        WHERE (_collection IS NULL OR collection = _collection)
          AND last_seen < now() - retention_interval
        RETURNING collection
    )
    SELECT collection, count(*)::int
    FROM deleted
    GROUP BY collection;
$$ LANGUAGE SQL VOLATILE;

-- register_field_paths: append-only registry upsert from a PRE-COMPUTED path set.
-- This is the seam for the Rust client (and any loader that already walked the
-- JSON): it sends the distinct field paths it found, and we skip the SQL-side
-- jsonb_field_rows walk entirely (set `pgstac.skip_field_registry = true` on the
-- ingest session so the staging trigger does not also walk — avoids double work).
-- _paths is a jsonb array of {path text, is_leaf bool, value_kinds text[]} objects.
CREATE OR REPLACE FUNCTION register_field_paths(_collection text, _paths jsonb)
RETURNS int AS $$
    WITH upserted AS (
        INSERT INTO item_field_registry (collection, path, is_leaf, value_kinds, first_seen, last_seen)
        SELECT
            _collection,
            p->>'path',
            coalesce((p->>'is_leaf')::boolean, true),
            coalesce(ARRAY(SELECT jsonb_array_elements_text(p->'value_kinds')), '{}'::text[]),
            now(), now()
        FROM jsonb_array_elements(_paths) AS p
        WHERE p->>'path' IS NOT NULL
        ON CONFLICT (collection, path) DO UPDATE SET
            is_leaf     = EXCLUDED.is_leaf,
            value_kinds = (SELECT array_agg(DISTINCT v)
                           FROM unnest(item_field_registry.value_kinds || EXCLUDED.value_kinds) t(v)),
            last_seen   = now()
        RETURNING 1
    )
    SELECT count(*)::int FROM upserted;
$$ LANGUAGE SQL VOLATILE;

-- Item Fragment Management functions

-- extract_fragment: Given full STAC item JSONB and a list of serialized fragment paths
-- (each element is fragment_path_text(text[]) — a JSON-array serialized root-relative path),
-- extract the sparse overlay JSONB that will be stored in item_fragments for dedup.
-- Returns NULL when fragment_paths is NULL or empty, or when no values are found.
-- Supports paths at any depth:
--   depth-1  (e.g. 'stac_version')                  → extracts the whole top-level key.
--   depth-2  (e.g. 'assets.thumbnail')               → extracts a named sub-key.
--   depth-3+ (e.g. 'assets.thumbnail.type')          → extracts a nested sub-sub-key,
--                                                       building a sparse nested JSONB.
-- Multiple paths sharing intermediate keys are merged correctly so that, for example,
-- 'assets.thumbnail.type' and 'assets.thumbnail.roles' together produce
-- {"assets": {"thumbnail": {"type": ..., "roles": ...}}} rather than overwriting.
CREATE OR REPLACE FUNCTION extract_fragment(
    content jsonb,
    fragment_paths text[]
) RETURNS jsonb AS $$
DECLARE
    result    jsonb := '{}'::jsonb;
    p         text;
    pth       text[];
    val       jsonb;
BEGIN
    IF content IS NULL OR fragment_paths IS NULL OR cardinality(fragment_paths) = 0 THEN
        RETURN NULL;
    END IF;

    FOREACH p IN ARRAY fragment_paths LOOP
        pth := fragment_path_array(p);
        IF pth IS NULL OR cardinality(pth) = 0 THEN CONTINUE; END IF;

        val := content #> pth;
        IF val IS NOT NULL THEN
            -- jsonb_set_nested creates intermediate empty objects as needed, so
            -- depth-3+ paths are handled correctly and multiple paths sharing the
            -- same intermediate keys are merged rather than overwritten.
            result := jsonb_set_nested(result, pth, val);
        END IF;
    END LOOP;

    IF result = '{}'::jsonb THEN RETURN NULL; END IF;
    RETURN result;
END;
$$ LANGUAGE PLPGSQL IMMUTABLE PARALLEL SAFE;

-- pgstac_hash_fragment: Hash a fragment payload for dedup. Returns the raw
-- 32-byte sha256 (bytea), stored directly in item_fragments.hash. The fragment
-- jsonb is normalized to a single canonical text by PostgreSQL (equal fragments
-- always serialize identically), so jsonb::text is sufficient for this
-- internal dedup key; the externally reproducible item digest is pgstac_item_hash.
CREATE OR REPLACE FUNCTION pgstac_hash_fragment(fragment jsonb) RETURNS bytea AS $$
SELECT sha256(convert_to(fragment::text, 'UTF8'));
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;

-- gc_fragments: Garbage collect orphaned fragments using a single set-based DELETE.
-- Replaces the previous per-collection FOR LOOP with a single statement that lets
-- the planner choose the optimal join/anti-join strategy across all collections.
-- The NOT EXISTS sub-select is evaluated per fragment; with an index on items.fragment_id
-- this is an efficient anti-join rather than a full seq-scan.
--
-- Operational note: because items.fragment_id is intentionally unmanaged by an FK
-- (partitioned-items incremental NOT VALID FKs are not supported), gc_fragments has a
-- small race window with concurrent inserts. A fragment that is unreferenced at the time
-- the DELETE snapshot is taken but becomes referenced by a later insert could be removed.
-- The retention_interval guard makes this unlikely for normal ingest, but operators should
-- still run gc_fragments during low-ingest periods or with a sufficiently conservative
-- retention interval. This is a documented operational tradeoff, not a silent invariant.
CREATE OR REPLACE FUNCTION gc_fragments(
    _collection text DEFAULT NULL,
    retention_interval interval DEFAULT '90 days'
) RETURNS TABLE (
    collection_id text,
    fragments_removed int
) AS $$
    WITH deleted AS (
        DELETE FROM item_fragments f
        WHERE
            (_collection IS NULL OR f.collection = _collection)
            AND f.created_at < now() - retention_interval
            AND NOT EXISTS (SELECT 1 FROM items i WHERE i.fragment_id = f.id)
        RETURNING f.collection
    )
    SELECT collection, count(*)::int
    FROM deleted
    GROUP BY collection;
$$ LANGUAGE SQL VOLATILE PARALLEL UNSAFE;

-- strip_fragment_col: Remove fragment-owned sub-keys from a split column value.
-- col_name is the top-level STAC key that this column represents (e.g. 'assets' or 'properties').
-- fragment_paths is the collection's fragment_config text[].
-- Supports paths at any depth:
--   depth-1  matching col_name  → zeroes out the entire column (returns '{}').
--   depth-2+ matching col_name  → removes the nested sub-path using the #- operator,
--                                  which handles arbitrary nesting without requiring a loop.
-- Examples with col_name='assets':
--   'assets'                  → returns '{}'  (whole column is in the fragment)
--   'assets.thumbnail'        → removes 'thumbnail' key  (depth-2, old behaviour)
--   'assets.thumbnail.type'   → removes 'type' from within 'thumbnail'  (depth-3, new)
-- Returns col_value unchanged when there are no matching fragment paths.
CREATE OR REPLACE FUNCTION strip_fragment_col(
    col_value jsonb,
    col_name  text,
    fragment_paths text[]
) RETURNS jsonb AS $$
DECLARE
    result    jsonb := col_value;
    p         text;
    pth       text[];
    n         int;
BEGIN
    IF col_value IS NULL OR fragment_paths IS NULL THEN RETURN col_value; END IF;

    FOREACH p IN ARRAY fragment_paths LOOP
        pth := fragment_path_array(p);
        n   := cardinality(pth);
        IF pth IS NULL OR n = 0 OR pth[1] <> col_name THEN CONTINUE; END IF;

        IF n = 1 THEN
            RETURN '{}'::jsonb;  -- entire column goes to fragment
        ELSE
            -- Remove the nested sub-path from the column value at any depth.
            -- #- handles depth-2 (removes a top-level key) through depth-N (removes a
            -- nested key) using the path tail pth[2:n].
            result := result #- pth[2:n];
        END IF;
    END LOOP;

    RETURN result;
END;
$$ LANGUAGE PLPGSQL IMMUTABLE PARALLEL SAFE;
-- END FRAGMENT: 003a_items.sql

-- BEGIN FRAGMENT: 003b_partitions.sql
-- partition_stats: the single source of per-partition metadata, used both for
-- maintenance and as the search-discovery index (chunker() reads it directly). Holds
-- the partition boundary (partition_dtrange) plus the actual data extents (dtrange,
-- edtrange, spatial) and a row estimate (n). NULL data extents mean a freshly created,
-- not-yet-analyzed partition (treated as unbounded by discovery).
CREATE TABLE partition_stats (
    partition text PRIMARY KEY,
    collection text,
    partition_dtrange tstzrange,
    dtrange tstzrange,
    edtrange tstzrange,
    spatial geometry,
    last_updated timestamptz,
    n bigint,
    keys text[]
) WITH (FILLFACTOR=90);

CREATE INDEX partitions_range_idx ON partition_stats USING GIST(dtrange);
CREATE INDEX partition_stats_collection_idx ON partition_stats (collection);
CREATE INDEX partition_stats_spatial_idx ON partition_stats USING GIST(spatial) WHERE spatial IS NOT NULL;


CREATE OR REPLACE FUNCTION constraint_tstzrange(expr text) RETURNS tstzrange AS $$
    WITH t AS (
        SELECT regexp_matches(
            expr,
            E'\\(''\([0-9 :+-]*\)''\\).*\\(''\([0-9 :+-]*\)''\\)'
        ) AS m
    ) SELECT tstzrange(m[1]::timestamptz, m[2]::timestamptz) FROM t
    ;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE STRICT;

CREATE OR REPLACE FUNCTION get_tstz_constraint(reloid oid, colname text) RETURNS tstzrange AS $$
DECLARE
    expr text := NULL;
    m text[];
    ts_lower timestamptz := NULL;
    ts_upper timestamptz := NULL;
    lower_inclusive text := '[';
    upper_inclusive text := ']';
    ts timestamptz;
BEGIN
    SELECT INTO expr
        string_agg(def, ' AND ')
    FROM pg_constraint JOIN LATERAL pg_get_constraintdef(oid) AS def ON TRUE
    WHERE
        conrelid = reloid
        AND contype = 'c'
        AND def LIKE '%' || colname || '%'
    ;

    IF expr IS NULL THEN
        RETURN NULL;
    END IF;

    RAISE DEBUG 'Constraint expression for % on %: %', colname, reloid::regclass, expr;
    -- collect all constraints for the specified column
    FOR m IN SELECT regexp_matches(expr, '[ (]' || colname || $expr$\s*([<>=]{1,2})\s*'([0-9 :.+\-]+)'$expr$, 'g') LOOP
        ts := m[2]::timestamptz;
        IF m[1] IN ('>', '>=')
        THEN
            IF ts_lower IS NULL OR ts > ts_lower OR (ts = ts_lower AND m[1] = '>') THEN
                ts_lower := ts;
                lower_inclusive := CASE WHEN m[1] = '>' THEN '(' ELSE '[' END;
            END IF;
        ELSIF m[1] IN ('<', '<=')
        THEN
            IF ts_upper IS NULL OR ts < ts_upper OR (ts = ts_upper AND m[1] = '<') THEN
                ts_upper := ts;
                upper_inclusive := CASE WHEN m[1] = '<' THEN ')' ELSE ']' END;
            END IF;
        END IF;
    END LOOP;
    RAISE DEBUG 'Constraint % for %: % %', colname, reloid::regclass, ts_lower, ts_upper;
    RETURN tstzrange(ts_lower, ts_upper, lower_inclusive || upper_inclusive);
END;
$$ LANGUAGE plpgsql STRICT STABLE;

CREATE OR REPLACE FUNCTION get_partition_name(relid regclass) RETURNS text AS $$
    SELECT (parse_ident(relid::text))[cardinality(parse_ident(relid::text))];
$$ LANGUAGE SQL STABLE STRICT;

CREATE OR REPLACE VIEW partition_sys_meta AS
SELECT
    partition,
    replace(
        replace(
            CASE WHEN level = 1 THEN partition_expr ELSE parent_partition_expr END,
            'FOR VALUES IN (''',
            ''
        ),
        ''')',
        ''
    ) AS collection,
    level,
    c.reltuples,
    c.relhastriggers,
    partition_dtrange,
    COALESCE(
        get_tstz_constraint(c.oid, 'datetime'),
        partition_dtrange,
        inf_range
    ) as constraint_dtrange,
    COALESCE(
        get_tstz_constraint(c.oid, 'end_datetime'),
        inf_range
    ) as constraint_edtrange
FROM
    pg_partition_tree('items')
    JOIN pg_class c ON (relid::regclass = c.oid)
    JOIN pg_class parent ON (parentrelid::regclass = parent.oid AND isleaf)
    LEFT JOIN pg_constraint edt ON (conrelid=c.oid AND contype='c')
    JOIN LATERAL get_partition_name(relid) AS partition ON TRUE
    JOIN LATERAL pg_get_expr(c.relpartbound, c.oid) as partition_expr ON TRUE
    JOIN LATERAL pg_get_expr(parent.relpartbound, parent.oid) as parent_partition_expr ON TRUE
    JOIN LATERAL tstzrange('-infinity', 'infinity','[]') as inf_range ON TRUE
    JOIN LATERAL COALESCE(constraint_tstzrange(pg_get_expr(c.relpartbound, c.oid)), inf_range) as partition_dtrange ON TRUE
    JOIN LATERAL get_tstz_constraint(c.oid, 'datetime') as datetime_constraint ON TRUE
    JOIN LATERAL get_tstz_constraint(c.oid, 'end_datetime') as end_datetime_constraint ON TRUE
WHERE isleaf
;

CREATE OR REPLACE VIEW partitions_view AS
SELECT
    (parse_ident(relid::text))[cardinality(parse_ident(relid::text))] as partition,
    replace(
        replace(
            CASE WHEN level = 1 THEN partition_expr ELSE parent_partition_expr END,
            'FOR VALUES IN (''',
            ''
        ),
        ''')',
        ''
    ) AS collection,
    level,
    c.reltuples,
    c.relhastriggers,
    partboundary AS partition_dtrange,
    COALESCE(
        get_tstz_constraint(c.oid, 'datetime'),
        partboundary,
        inf_range
    ) as constraint_dtrange,
    COALESCE(
        get_tstz_constraint(c.oid, 'end_datetime'),
        inf_range
    ) as constraint_edtrange,
    dtrange,
    edtrange,
    spatial,
    last_updated
FROM
    pg_partition_tree('items')
    JOIN pg_class c ON (relid::regclass = c.oid)
    JOIN pg_class parent ON (parentrelid::regclass = parent.oid AND isleaf)
    LEFT JOIN pg_constraint edt ON (conrelid=c.oid AND contype='c')
    JOIN LATERAL get_partition_name(relid) AS partition ON TRUE
    JOIN LATERAL pg_get_expr(c.relpartbound, c.oid) as partition_expr ON TRUE
    JOIN LATERAL pg_get_expr(parent.relpartbound, parent.oid) as parent_partition_expr ON TRUE
    JOIN LATERAL tstzrange('-infinity', 'infinity','[]') as inf_range ON TRUE
    JOIN LATERAL COALESCE(constraint_tstzrange(pg_get_expr(c.relpartbound, c.oid)), inf_range) as partboundary ON TRUE
    JOIN LATERAL get_tstz_constraint(c.oid, 'datetime') as datetime_constraint ON TRUE
    JOIN LATERAL get_tstz_constraint(c.oid, 'end_datetime') as end_datetime_constraint ON TRUE
    LEFT JOIN pgstac.partition_stats USING (partition)
WHERE isleaf
;

-- Backfill / self-heal the boundary metadata (collection, partition_dtrange, n) in
-- partition_stats from the authoritative live partition tree, and drop rows whose
-- partition no longer exists. The data extents (dtrange/edtrange/spatial) are filled
-- separately by update_partition_stats() after ANALYZE. Cheap (one pass).
CREATE OR REPLACE FUNCTION sync_partition_stats() RETURNS bigint AS $$
    WITH upserted AS (
        INSERT INTO partition_stats AS ps (partition, collection, partition_dtrange, n)
        SELECT
            p.partition, p.collection, p.partition_dtrange,
            (SELECT reltuples::bigint FROM pg_class WHERE oid = quote_ident(p.partition)::regclass)
        FROM partition_sys_meta p
        ON CONFLICT (partition) DO UPDATE SET
            collection = EXCLUDED.collection,
            partition_dtrange = EXCLUDED.partition_dtrange,
            n = COALESCE(EXCLUDED.n, ps.n)
        RETURNING ps.partition
    ),
    deleted AS (
        DELETE FROM partition_stats d
        WHERE NOT EXISTS (SELECT 1 FROM partition_sys_meta m WHERE m.partition = d.partition)
        RETURNING 1
    )
    SELECT (SELECT count(*) FROM upserted);
$$ LANGUAGE SQL SECURITY DEFINER SET search_path TO pgstac, public;


CREATE OR REPLACE FUNCTION update_partition_stats_q(_partition text, istrigger boolean default false) RETURNS VOID AS $$
DECLARE
BEGIN
    PERFORM run_or_queue(
        format('SELECT update_partition_stats(%L, %L);', _partition, istrigger)
    );
END;
$$ LANGUAGE PLPGSQL;

CREATE OR REPLACE FUNCTION update_partition_stats(_partition text, istrigger boolean default false) RETURNS VOID AS $$
DECLARE
    dtrange tstzrange;
    edtrange tstzrange;
    extent geometry;
    collection text;
    _part_dtrange tstzrange;
    _reltuples bigint;
BEGIN
    RAISE NOTICE 'Updating stats for %.', _partition;
    EXECUTE format(
        $q$
            SELECT
                tstzrange(min(datetime), max(datetime),'[]'),
                tstzrange(min(end_datetime), max(end_datetime), '[]')
            FROM %I
        $q$,
        _partition
    ) INTO dtrange, edtrange;
    EXECUTE format('ANALYZE %I;', _partition);
    extent := st_estimatedextent('pgstac', _partition, 'geometry');
    RAISE DEBUG 'Estimated Extent: %', extent;

    SELECT pv.collection, pv.partition_dtrange INTO collection, _part_dtrange
    FROM partitions_view pv WHERE partition = _partition;
    _reltuples := (SELECT reltuples::bigint FROM pg_class WHERE oid = quote_ident(_partition)::regclass);

    -- partition_stats is the single source: write the boundary + data extents + row
    -- estimate together (row lock only, no MV refresh).
    INSERT INTO partition_stats
        (partition, collection, partition_dtrange, dtrange, edtrange, spatial, n, last_updated)
        SELECT _partition, collection, _part_dtrange, dtrange, edtrange, extent, _reltuples, now()
        ON CONFLICT (partition) DO
            UPDATE SET
                collection=EXCLUDED.collection,
                partition_dtrange=EXCLUDED.partition_dtrange,
                dtrange=EXCLUDED.dtrange,
                edtrange=EXCLUDED.edtrange,
                spatial=EXCLUDED.spatial,
                n=EXCLUDED.n,
                last_updated=EXCLUDED.last_updated
    ;

    IF get_setting_bool('update_collection_extent') THEN
        RAISE NOTICE 'updating collection extent for %', collection;
        PERFORM run_or_queue(format($q$
            UPDATE collections
            SET content = jsonb_set_lax(
                content,
                '{extent}'::text[],
                collection_extent(%L, FALSE),
                true,
                'use_json_null'
            ) WHERE id=%L
            ;
        $q$, collection, collection));
    ELSE
        RAISE NOTICE 'Not updating collection extent for %', collection;
    END IF;

END;
$$ LANGUAGE PLPGSQL STRICT SECURITY DEFINER;


CREATE OR REPLACE FUNCTION partition_name( IN collection text, IN dt timestamptz, OUT partition_name text, OUT partition_range tstzrange) AS $$
DECLARE
    c RECORD;
    parent_name text;
BEGIN
    SELECT * INTO c FROM pgstac.collections WHERE id=collection;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Collection % does not exist', collection USING ERRCODE = 'foreign_key_violation', HINT = 'Make sure collection exists before adding items';
    END IF;
    parent_name := format('_items_%s', c.key);


    IF c.partition_trunc = 'year' THEN
        partition_name := format('%s_%s', parent_name, to_char(dt,'YYYY'));
    ELSIF c.partition_trunc = 'month' THEN
        partition_name := format('%s_%s', parent_name, to_char(dt,'YYYYMM'));
    ELSE
        partition_name := parent_name;
        partition_range := tstzrange('-infinity'::timestamptz, 'infinity'::timestamptz, '[]');
    END IF;
    IF partition_range IS NULL THEN
        partition_range := tstzrange(
            date_trunc(c.partition_trunc::text, dt),
            date_trunc(c.partition_trunc::text, dt) + concat('1 ', c.partition_trunc)::interval
        );
    END IF;
    RETURN;

END;
$$ LANGUAGE PLPGSQL STABLE;


CREATE OR REPLACE FUNCTION drop_table_constraints(t text) RETURNS text AS $$
DECLARE
    q text;
BEGIN
    IF NOT EXISTS (SELECT 1 FROM partitions_view WHERE partition=t) THEN
        RETURN NULL;
    END IF;
    FOR q IN SELECT FORMAT(
        $q$
            ALTER TABLE %I DROP CONSTRAINT IF EXISTS %I;
        $q$,
        t,
        conname
    ) FROM pg_constraint
        WHERE conrelid=t::regclass::oid AND contype='c'
    LOOP
        EXECUTE q;
    END LOOP;
    RETURN t;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION create_table_constraints(t text, _dtrange tstzrange, _edtrange tstzrange) RETURNS text AS $$
DECLARE
    q text;
BEGIN
    IF NOT EXISTS (SELECT 1 FROM partitions_view WHERE partition=t) THEN
        RETURN NULL;
    END IF;
    RAISE NOTICE 'Creating Table Constraints for % % %', t, _dtrange, _edtrange;
    IF _dtrange = 'empty' AND _edtrange = 'empty' THEN
        q :=format(
            $q$
                DO $block$
                BEGIN
                    ALTER TABLE %I DROP CONSTRAINT IF EXISTS %I;
                    ALTER TABLE %I
                        ADD CONSTRAINT %I
                            CHECK (((datetime IS NULL) AND (end_datetime IS NULL))) NOT VALID
                    ;
                    ALTER TABLE %I
                        VALIDATE CONSTRAINT %I
                    ;



                EXCEPTION WHEN others THEN
                    RAISE WARNING '%%, Issue Altering Constraints. Please run update_partition_stats(%I)', SQLERRM USING ERRCODE = SQLSTATE;
                END;
                $block$;
            $q$,
            t,
            format('%s_dt', t),
            t,
            format('%s_dt', t),
            t,
            format('%s_dt', t),
            t
        );
    ELSE
        q :=format(
            $q$
                DO $block$
                BEGIN

                    ALTER TABLE %I DROP CONSTRAINT IF EXISTS %I;
                    ALTER TABLE %I
                        ADD CONSTRAINT %I
                            CHECK (
                                (datetime >= %L)
                                AND (datetime <= %L)
                                AND (end_datetime >= %L)
                                AND (end_datetime <= %L)
                            ) NOT VALID
                    ;
                    ALTER TABLE %I
                        VALIDATE CONSTRAINT %I
                    ;



                EXCEPTION WHEN others THEN
                    RAISE WARNING '%%, Issue Altering Constraints. Please run update_partition_stats(%I)', SQLERRM USING ERRCODE = SQLSTATE;
                END;
                $block$;
            $q$,
            t,
            format('%s_dt', t),
            t,
            format('%s_dt', t),
            lower(_dtrange),
            upper(_dtrange),
            lower(_edtrange),
            upper(_edtrange),
            t,
            format('%s_dt', t),
            t
        );
    END IF;
    PERFORM run_or_queue(q);
    RETURN t;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;


CREATE OR REPLACE FUNCTION check_partition(
    _collection text,
    _dtrange tstzrange,
    _edtrange tstzrange
) RETURNS text AS $$
DECLARE
    c RECORD;
    pm RECORD;
    _partition_name text;
    _partition_dtrange tstzrange;
    _constraint_dtrange tstzrange;
    _constraint_edtrange tstzrange;
    q text;
    deferrable_q text;
    err_context text;
BEGIN
    SELECT * INTO c FROM pgstac.collections WHERE id=_collection;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Collection % does not exist', _collection USING ERRCODE = 'foreign_key_violation', HINT = 'Make sure collection exists before adding items';
    END IF;

    IF c.partition_trunc IS NOT NULL THEN
        _partition_dtrange := tstzrange(
            date_trunc(c.partition_trunc, lower(_dtrange)),
            date_trunc(c.partition_trunc, lower(_dtrange)) + (concat('1 ', c.partition_trunc))::interval,
            '[)'
        );
    ELSE
        _partition_dtrange :=  '[-infinity, infinity]'::tstzrange;
    END IF;

    IF NOT _partition_dtrange @> _dtrange THEN
        RAISE EXCEPTION 'dtrange % is greater than the partition size % for collection %', _dtrange, c.partition_trunc, _collection;
    END IF;


    IF c.partition_trunc = 'year' THEN
        _partition_name := format('_items_%s_%s', c.key, to_char(lower(_partition_dtrange),'YYYY'));
    ELSIF c.partition_trunc = 'month' THEN
        _partition_name := format('_items_%s_%s', c.key, to_char(lower(_partition_dtrange),'YYYYMM'));
    ELSE
        _partition_name := format('_items_%s', c.key);
    END IF;

    SELECT * INTO pm FROM partition_sys_meta WHERE collection=_collection AND partition_dtrange @> _dtrange;
    IF FOUND THEN
        RAISE NOTICE '% % %', _edtrange, _dtrange, pm;
        _constraint_edtrange :=
            tstzrange(
                least(
                    lower(_edtrange),
                    nullif(lower(pm.constraint_edtrange), '-infinity')
                ),
                greatest(
                    upper(_edtrange),
                    nullif(upper(pm.constraint_edtrange), 'infinity')
                ),
                '[]'
            );
        _constraint_dtrange :=
            tstzrange(
                least(
                    lower(_dtrange),
                    nullif(lower(pm.constraint_dtrange), '-infinity')
                ),
                greatest(
                    upper(_dtrange),
                    nullif(upper(pm.constraint_dtrange), 'infinity')
                ),
                '[]'
            );

        IF pm.constraint_edtrange @> _edtrange AND pm.constraint_dtrange @> _dtrange THEN
            RETURN pm.partition;
        ELSE
            PERFORM drop_table_constraints(_partition_name);
        END IF;
    ELSE
        _constraint_edtrange := _edtrange;
        _constraint_dtrange := _dtrange;
    END IF;
    RAISE NOTICE 'EXISTING CONSTRAINTS % %, NEW % %', pm.constraint_dtrange, pm.constraint_edtrange, _constraint_dtrange, _constraint_edtrange;
    RAISE NOTICE 'Creating partition % %', _partition_name, _partition_dtrange;
    IF c.partition_trunc IS NULL THEN
        q := format(
            $q$
                CREATE TABLE IF NOT EXISTS %I partition OF items FOR VALUES IN (%L);
                CREATE UNIQUE INDEX IF NOT EXISTS %I ON %I (id);
                GRANT ALL ON %I to pgstac_ingest;
            $q$,
            _partition_name,
            _collection,
            concat(_partition_name,'_pk'),
            _partition_name,
            _partition_name
        );
    ELSE
        q := format(
            $q$
                CREATE TABLE IF NOT EXISTS %I partition OF items FOR VALUES IN (%L) PARTITION BY RANGE (datetime);
                CREATE TABLE IF NOT EXISTS %I partition OF %I FOR VALUES FROM (%L) TO (%L);
                CREATE UNIQUE INDEX IF NOT EXISTS %I ON %I (id);
                GRANT ALL ON %I TO pgstac_ingest;
            $q$,
            format('_items_%s', c.key),
            _collection,
            _partition_name,
            format('_items_%s', c.key),
            lower(_partition_dtrange),
            upper(_partition_dtrange),
            format('%s_pk', _partition_name),
            _partition_name,
            _partition_name
        );
    END IF;

    BEGIN
        EXECUTE q;
    EXCEPTION
        WHEN duplicate_table THEN
            RAISE NOTICE 'Partition % already exists.', _partition_name;
        WHEN others THEN
            GET STACKED DIAGNOSTICS err_context = PG_EXCEPTION_CONTEXT;
            RAISE INFO 'Error Name:%',SQLERRM;
            RAISE INFO 'Error State:%', SQLSTATE;
            RAISE INFO 'Error Context:%', err_context;
    END;
    -- Register the partition_stats row immediately (boundary known; data extents filled
    -- when stats run). Ensures chunker() sees the partition even before stats queue.
    INSERT INTO partition_stats (partition, collection, partition_dtrange)
        VALUES (_partition_name, _collection, _partition_dtrange)
        ON CONFLICT (partition) DO UPDATE SET
            collection = EXCLUDED.collection,
            partition_dtrange = EXCLUDED.partition_dtrange;
    PERFORM maintain_partitions(_partition_name);
    PERFORM update_partition_stats_q(_partition_name, true);
    RETURN _partition_name;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;


CREATE OR REPLACE FUNCTION repartition(_collection text, _partition_trunc text, triggered boolean DEFAULT FALSE) RETURNS text AS $$
DECLARE
    c RECORD;
    q text;
    from_trunc text;
BEGIN
    SELECT * INTO c FROM pgstac.collections WHERE id=_collection;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Collection % does not exist', _collection USING ERRCODE = 'foreign_key_violation', HINT = 'Make sure collection exists before adding items';
    END IF;
    IF triggered THEN
        RAISE NOTICE 'Converting % to % partitioning via Trigger', _collection, _partition_trunc;
    ELSE
        RAISE NOTICE 'Converting % from using % to % partitioning', _collection, c.partition_trunc, _partition_trunc;
        IF c.partition_trunc IS NOT DISTINCT FROM _partition_trunc THEN
            RAISE NOTICE 'Collection % already set to use partition by %', _collection, _partition_trunc;
            RETURN _collection;
        END IF;
    END IF;

    IF EXISTS (SELECT 1 FROM partitions_view WHERE collection=_collection LIMIT 1) THEN
        -- The collection's partition tree is about to be dropped & rebuilt; clear its
        -- stale partition_stats rows (check_partition re-adds them as leaves recreate).
        DELETE FROM partition_stats WHERE collection=_collection;
        EXECUTE format(
            $q$
                CREATE TEMP TABLE changepartitionstaging ON COMMIT DROP AS SELECT * FROM %I;
                DROP TABLE IF EXISTS %I CASCADE;
                WITH p AS (
                    SELECT
                        collection,
                        CASE
                            WHEN %L IS NULL THEN '-infinity'::timestamptz
                            ELSE date_trunc(%L, datetime)
                        END as d,
                        tstzrange(min(datetime),max(datetime),'[]') as dtrange,
                        tstzrange(min(end_datetime),max(end_datetime),'[]') as edtrange
                    FROM changepartitionstaging
                    GROUP BY 1,2
                ) SELECT check_partition(collection, dtrange, edtrange) FROM p;
                INSERT INTO items SELECT * FROM changepartitionstaging;
                DROP TABLE changepartitionstaging;
            $q$,
            concat('_items_', c.key),
            concat('_items_', c.key),
            c.partition_trunc,
            c.partition_trunc
        );
    END IF;
    RETURN _collection;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION collections_trigger_func() RETURNS TRIGGER AS $$
DECLARE
    q text;
    partition_name text := format('_items_%s', NEW.key);
    partition_exists boolean := false;
    partition_empty boolean := true;
    err_context text;
    loadtemp boolean := FALSE;
BEGIN
    RAISE NOTICE 'Collection Trigger. % %', NEW.id, NEW.key;
    IF TG_OP = 'UPDATE' AND NEW.partition_trunc IS DISTINCT FROM OLD.partition_trunc THEN
        PERFORM repartition(NEW.id, NEW.partition_trunc, TRUE);
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE PLPGSQL;


CREATE TRIGGER collections_trigger AFTER
INSERT
OR
UPDATE ON collections
FOR EACH ROW EXECUTE FUNCTION collections_trigger_func();


-- partition_sync_meta: the CHEAP, metadata-first sync signal. For each partition of a
-- collection it returns the boundary range, a row-count estimate, and last_updated --
-- the time the partition's stats were last recomputed (which happens whenever items are
-- loaded into it). Read straight from partition_stats, no item scan. Sync compares
-- last_updated (and the count) to decide what changed; the exact content hash below is
-- used only as a fallback to prove equality when the metadata is ambiguous, so hashing
-- millions of rows never sits on the common sync path.
CREATE OR REPLACE FUNCTION partition_sync_meta(_collection text)
RETURNS TABLE(partition text, dtrange tstzrange, item_count bigint, last_updated timestamptz) AS $$
    SELECT partition, partition_dtrange, n, last_updated
    FROM partition_stats
    WHERE collection = _collection
    ORDER BY partition_dtrange;
$$ LANGUAGE sql STABLE PARALLEL SAFE;

-- partition_hashes: exact per-partition content fingerprint -- the FALLBACK that proves
-- whether a partition really changed when partition_sync_meta() is ambiguous (e.g.
-- last_updated differs but the content may be identical). content_hash = sha256 of the
-- comma-joined hex item_hashes ordered by id; empty partition -> sha256 of the empty
-- string. O(n) per partition, so callers should gate it behind the cheap metadata
-- check rather than run it on every sync. Sync/maintenance op, not a hot path.
--
-- Membership is by datetime range (i.datetime <@ p.partition_dtrange), which mirrors
-- how items are physically routed and lets the planner prune to the matching
-- partition. Caveat: an item with a NULL datetime (only possible in a collection that
-- is LIST-partitioned by collection without datetime sub-partitioning) does not match
-- any range and is therefore not counted/hashed; such items are outside the STAC
-- temporal model. A future variant could group by physical partition (i.tableoid) if
-- NULL-datetime items must be fingerprinted.
CREATE OR REPLACE FUNCTION partition_hashes(_collection text)
RETURNS TABLE(partition text, dtrange tstzrange, item_count bigint, content_hash text) AS $$
    SELECT
        p.partition,
        p.partition_dtrange,
        count(i.id),
        encode(sha256(convert_to(
            coalesce(string_agg(encode(i.item_hash, 'hex'), ',' ORDER BY i.id), ''),
            'UTF8')), 'hex')
    FROM partition_sys_meta p
    LEFT JOIN items i
        ON i.collection = p.collection
       AND i.datetime <@ p.partition_dtrange
    WHERE p.collection = _collection
    GROUP BY p.partition, p.partition_dtrange
    ORDER BY p.partition_dtrange;
$$ LANGUAGE sql STABLE PARALLEL SAFE;
-- END FRAGMENT: 003b_partitions.sql

-- BEGIN FRAGMENT: 004_search.sql

-- chunker (v0.10 discovery): prune partition_stats candidates by collection + the
-- predicate envelope (temporal multiranges + spatial bbox), then build merged disjoint
-- datetime bands from the candidates' partition boundaries (contiguous → clean band set).
-- Pure indexed SELECT on partition_stats -- no EXPLAIN and no materialized view.
-- The envelope is a safe over-approximation, so this returns a SUPERSET of touched bands;
-- exact correctness is enforced by each band query's WHERE. NULL data-extents (a freshly
-- created, not-yet-analyzed partition) are treated as unbounded → always included.
CREATE OR REPLACE FUNCTION chunker(
    _env pred_envelope,
    OUT s timestamptz,
    OUT e timestamptz
) RETURNS SETOF record LANGUAGE sql STABLE AS $$
    WITH cand AS (
        SELECT lower(ps.partition_dtrange) AS part_lo, upper(ps.partition_dtrange) AS part_hi
        FROM partition_stats ps
        WHERE ((_env).colls IS NULL OR ps.collection = ANY ((_env).colls))
          AND (_env).dt  && COALESCE(ps.dtrange,  tstzrange('-infinity', 'infinity', '[]'))
          AND (_env).edt && COALESCE(ps.edtrange, tstzrange('-infinity', 'infinity', '[]'))
          AND ((_env).geom IS NULL OR ps.spatial IS NULL OR ps.spatial && (_env).geom)
    ),
    bnds AS (
        SELECT part_lo AS t FROM cand WHERE part_lo IS NOT NULL
        UNION SELECT part_hi FROM cand WHERE part_hi IS NOT NULL
    ),
    uniq AS (SELECT DISTINCT t FROM bnds),
    bands AS (SELECT t AS s, lead(t) OVER (ORDER BY t) AS e FROM uniq)
    SELECT b.s, b.e FROM bands b WHERE b.e IS NOT NULL;
$$;

CREATE OR REPLACE FUNCTION q_to_tsquery (jinput jsonb)
    RETURNS tsquery
    AS $$
DECLARE
    input text;
    processed_text text;
    temp_text text;
    quote_array text[];
    placeholder text := '@QUOTE@';
BEGIN
    IF jsonb_typeof(jinput) = 'string' THEN
        input := jinput->>0;
    ELSIF jsonb_typeof(jinput) = 'array' THEN
        input := array_to_string(
            array(select jsonb_array_elements_text(jinput)),
            ' OR '
        );
    ELSE
        RAISE EXCEPTION 'Input must be a string or an array of strings.';
    END IF;
    -- Extract all quoted phrases and store in array
    quote_array := regexp_matches(input, '"[^"]*"', 'g');

    -- Replace each quoted part with a unique placeholder if there are any quoted phrases
    IF array_length(quote_array, 1) IS NOT NULL THEN
        processed_text := input;
        FOR i IN array_lower(quote_array, 1) .. array_upper(quote_array, 1) LOOP
            processed_text := replace(processed_text, quote_array[i], placeholder || i || placeholder);
        END LOOP;
    ELSE
        processed_text := input;
    END IF;

    -- Replace non-quoted text using regular expressions

    -- , -> |
    processed_text := regexp_replace(processed_text, ',(?=(?:[^"]*"[^"]*")*[^"]*$)', ' | ', 'g');

    -- and -> &
    processed_text := regexp_replace(processed_text, '\s+AND\s+', ' & ', 'gi');

    -- or -> |
    processed_text := regexp_replace(processed_text, '\s+OR\s+', ' | ', 'gi');

    -- + ->
    processed_text := regexp_replace(processed_text, '^\s*\+([a-zA-Z0-9_]+)', '\1', 'g'); -- +term at start
    processed_text := regexp_replace(processed_text, '\s*\+([a-zA-Z0-9_]+)', ' & \1', 'g'); -- +term elsewhere

    -- - ->  !
    processed_text := regexp_replace(processed_text, '^\s*\-([a-zA-Z0-9_]+)', '! \1', 'g'); -- -term at start
    processed_text := regexp_replace(processed_text, '\s*\-([a-zA-Z0-9_]+)', ' & ! \1', 'g'); -- -term elsewhere

    -- terms separated with spaces are assumed to represent adjacent terms. loop through these
    -- occurrences and replace them with the adjacency operator (<->)
    LOOP
        temp_text := regexp_replace(processed_text, '([a-zA-Z0-9_]+)\s+([a-zA-Z0-9_]+)(?!\s*[&|<>])', '\1 <-> \2', 'g');
        IF temp_text = processed_text THEN
            EXIT; -- No more replacements were made
        END IF;
        processed_text := temp_text;
    END LOOP;


    -- Replace placeholders back with quoted phrases if there were any
    IF array_length(quote_array, 1) IS NOT NULL THEN
        FOR i IN array_lower(quote_array, 1) .. array_upper(quote_array, 1) LOOP
            processed_text := replace(processed_text, placeholder || i || placeholder, '''' || substring(quote_array[i] from 2 for length(quote_array[i]) - 2) || '''');
        END LOOP;
    END IF;

    RETURN to_tsquery('english', processed_text);
END;
$$
LANGUAGE plpgsql;


-- Build the SQL WHERE clause for a STAC search. Every parameter (ids, collections,
-- datetime, bbox/intersects, q, query, filter) is normalized into one CQL2 filter by
-- search_to_cql2() and translated by cql2_query() -- the same single representation
-- that drives partition pruning via cql2_envelope(). Returns ' TRUE ' for a match-all
-- (empty) search.
CREATE OR REPLACE FUNCTION stac_search_to_where(j jsonb) RETURNS text AS $$
DECLARE
    _where text := cql2_query(search_to_cql2(j));
BEGIN
    IF _where IS NULL OR BTRIM(_where) = '' THEN
        RETURN ' TRUE ';
    END IF;
    RETURN _where;
END;
$$ LANGUAGE PLPGSQL STABLE;


CREATE OR REPLACE FUNCTION parse_sort_dir(_dir text, reverse boolean default false) RETURNS text AS $$
    WITH t AS (
        SELECT COALESCE(upper(_dir), 'ASC') as d
    ) SELECT
        CASE
            WHEN NOT reverse THEN d
            WHEN d = 'ASC' THEN 'DESC'
            WHEN d = 'DESC' THEN 'ASC'
        END
    FROM t;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;

CREATE OR REPLACE FUNCTION sort_dir_to_op(_dir text, prev boolean default false) RETURNS text AS $$
    WITH t AS (
        SELECT COALESCE(upper(_dir), 'ASC') as d
    ) SELECT
        CASE
            WHEN d = 'ASC' AND prev THEN '<='
            WHEN d = 'DESC' AND prev THEN '>='
            WHEN d = 'ASC' THEN '>='
            WHEN d = 'DESC' THEN '<='
        END
    FROM t;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;


CREATE OR REPLACE FUNCTION sort_sqlorderby(
    _search jsonb DEFAULT NULL,
    reverse boolean DEFAULT FALSE
) RETURNS text AS $$
    WITH sortby AS (
        SELECT coalesce(_search->'sortby','[{"field":"datetime", "direction":"desc"}]') as sort
    ), withid AS (
        SELECT CASE
            WHEN sort @? '$[*] ? (@.field == "id")' THEN sort
            ELSE sort || '[{"field":"id", "direction":"desc"}]'::jsonb
            END as sort
        FROM sortby
    ), withid_rows AS (
        SELECT jsonb_array_elements(sort) as value FROM withid
    ),sorts AS (
        SELECT
            coalesce(
                (queryable(value->>'field')).expression
            ) as key,
            parse_sort_dir(value->>'direction', reverse) as dir
        FROM withid_rows
    )
    SELECT array_to_string(
        array_agg(concat(key, ' ', dir)),
        ', '
    ) FROM sorts;
$$ LANGUAGE SQL;

CREATE OR REPLACE FUNCTION get_sort_dir(sort_item jsonb) RETURNS text AS $$
    SELECT CASE WHEN sort_item->>'direction' ILIKE 'desc%' THEN 'DESC' ELSE 'ASC' END;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;


CREATE OR REPLACE FUNCTION  get_token_val_str(
    _field text,
    _item items
) RETURNS text AS $$
DECLARE
    q text;
    literal text;
BEGIN
    q := format($q$ SELECT quote_literal(%s) FROM (SELECT $1.*) as r;$q$, _field);
    EXECUTE q INTO literal USING _item;
    RETURN literal;
END;
$$ LANGUAGE PLPGSQL;



CREATE OR REPLACE FUNCTION get_token_record(IN _token text, OUT prev BOOLEAN, OUT item items) RETURNS RECORD AS $$
DECLARE
    _itemid text := _token;
    _collectionid text;
BEGIN
    IF _token IS NULL THEN
        RETURN;
    END IF;
    RAISE NOTICE 'Looking for token: %', _token;
    prev := FALSE;
    IF _token ILIKE 'prev:%' THEN
        _itemid := replace(_token, 'prev:','');
        prev := TRUE;
    ELSIF _token ILIKE 'next:%' THEN
        _itemid := replace(_token, 'next:', '');
    END IF;
    SELECT id INTO _collectionid FROM collections WHERE _itemid LIKE concat(id,':%');
    IF FOUND THEN
        _itemid := replace(_itemid, concat(_collectionid,':'), '');
        SELECT * INTO item FROM items WHERE id=_itemid AND collection=_collectionid;
    ELSE
        SELECT * INTO item FROM items WHERE id=_itemid;
    END IF;
    IF item IS NULL THEN
        RAISE EXCEPTION 'Could not find item using token: % item: % collection: %', _token, _itemid, _collectionid;
    END IF;
    RETURN;
END;
$$ LANGUAGE PLPGSQL STABLE STRICT;


CREATE OR REPLACE FUNCTION get_token_filter(
    _sortby jsonb DEFAULT '[{"field":"datetime","direction":"desc"}]'::jsonb,
    token_item items DEFAULT NULL,
    prev boolean DEFAULT FALSE,
    inclusive boolean DEFAULT FALSE
) RETURNS text AS $$
DECLARE
    ltop text := '<';
    gtop text := '>';
    dir text;
    sort record;
    orfilter text := '';
    orfilters text[] := '{}'::text[];
    andfilters text[] := '{}'::text[];
    output text;
    token_where text;
BEGIN
    IF _sortby IS NULL OR _sortby = '[]'::jsonb THEN
        _sortby := '[{"field":"datetime","direction":"desc"}]'::jsonb;
    END IF;
    _sortby := _sortby || jsonb_build_object('field','id','direction',_sortby->0->>'direction');
    RAISE NOTICE 'Getting Token Filter. % %', _sortby, token_item;
    IF inclusive THEN
        orfilters := orfilters || format('( id=%L AND collection=%L )' , token_item.id, token_item.collection);
    END IF;

    FOR sort IN
        WITH s1 AS (
            SELECT
                _row,
                (queryable(value->>'field')).expression as _field,
                (value->>'field' = 'id') as _isid,
                get_sort_dir(value) as _dir
            FROM jsonb_array_elements(_sortby)
            WITH ORDINALITY AS t(value, _row)
        )
        SELECT
            _row,
            _field,
            _dir,
            get_token_val_str(_field, token_item) as _val
        FROM s1
        WHERE _row <= (SELECT min(_row) FROM s1 WHERE _isid)
    LOOP
        orfilter := NULL;
        RAISE NOTICE 'SORT: %', sort;
        IF sort._val IS NOT NULL AND  ((prev AND sort._dir = 'ASC') OR (NOT prev AND sort._dir = 'DESC')) THEN
            orfilter := format($f$(
                (%s %s %s) OR (%s IS NULL)
            )$f$,
            sort._field,
            ltop,
            sort._val,
            sort._val
            );
        ELSIF sort._val IS NULL AND  ((prev AND sort._dir = 'ASC') OR (NOT prev AND sort._dir = 'DESC')) THEN
            RAISE NOTICE '< but null';
            orfilter := format('%s IS NOT NULL', sort._field);
        ELSIF sort._val IS NULL THEN
            RAISE NOTICE '> but null';
        ELSE
            orfilter := format($f$(
                (%s %s %s) OR (%s IS NULL)
            )$f$,
            sort._field,
            gtop,
            sort._val,
            sort._field
            );
        END IF;
        RAISE NOTICE 'ORFILTER: %', orfilter;

        IF orfilter IS NOT NULL THEN
            IF sort._row = 1 THEN
                orfilters := orfilters || orfilter;
            ELSE
                orfilters := orfilters || format('(%s AND %s)', array_to_string(andfilters, ' AND '), orfilter);
            END IF;
        END IF;
        IF sort._val IS NOT NULL THEN
            andfilters := andfilters || format('%s = %s', sort._field, sort._val);
        ELSE
            andfilters := andfilters || format('%s IS NULL', sort._field);
        END IF;
    END LOOP;

    output := array_to_string(orfilters, ' OR ');

    token_where := concat('(',coalesce(output,'true'),')');
    IF trim(token_where) = '' THEN
        token_where := NULL;
    END IF;
    RAISE NOTICE 'TOKEN_WHERE: %',token_where;
    RETURN token_where;
    END;
$$ LANGUAGE PLPGSQL SET transform_null_equals TO TRUE
;

-- ============================================================================
-- Search Hashing
-- ============================================================================

CREATE OR REPLACE FUNCTION pgstac_hash(data text) RETURNS text AS $$
    SELECT encode(sha256(convert_to(data, 'UTF8')), 'hex');
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE STRICT;

-- Central hash helper: one canonical where-clause + metadata payload to hash.
CREATE OR REPLACE FUNCTION search_hash_from_where(_where text, _metadata jsonb DEFAULT '{}'::jsonb) RETURNS text AS $$
    SELECT pgstac_hash(
        format(
            '%s|%s',
            _where,
            coalesce(_metadata, '{}'::jsonb)::text
        )
    );
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;

CREATE OR REPLACE FUNCTION search_hash(_search jsonb, _metadata jsonb DEFAULT '{}'::jsonb) RETURNS text AS $$
    SELECT search_hash_from_where(
        stac_search_to_where(_search),
        _metadata
    );
$$ LANGUAGE SQL STABLE PARALLEL SAFE;

-- ============================================================================
-- Search Cache Table
-- ============================================================================

-- Search lifecycle and context cache now live on searches; search_wheres is retired.
CREATE TABLE IF NOT EXISTS searches(
    hash text PRIMARY KEY,
    name text UNIQUE,
    search jsonb NOT NULL,
    _where text,
    orderby text,
    lastused timestamptz DEFAULT now(),
    usecount bigint DEFAULT 0,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    pinned boolean NOT NULL DEFAULT false,
    created_at timestamptz DEFAULT now(),
    statslastupdated timestamptz,
    context_count bigint
);
CREATE INDEX IF NOT EXISTS searches_lastused_anon_idx
    ON searches (lastused) WHERE name IS NULL AND NOT pinned;

DROP TABLE IF EXISTS search_wheres;

-- ============================================================================
-- Context Stats (estimate/count/TTL)
-- ============================================================================

CREATE OR REPLACE FUNCTION where_stats(
    inhash text,
    inwhere text,
    updatestats boolean default false,
    conf jsonb default null
) RETURNS searches AS $$
DECLARE
    t timestamptz;
    i interval;
    explain_json jsonb;
    sw searches%ROWTYPE;
    sw_statslastupdated timestamptz;
    sw_estimated_count bigint;
    sw_estimated_cost float;
    _context text := lower(context(conf));
    _stats_ttl interval := context_stats_ttl(conf);
    _estimated_cost_threshold float := context_estimated_cost(conf);
    _estimated_count_threshold int := context_estimated_count(conf);
    ro bool := pgstac.readonly(conf);
BEGIN
    -- If updatestats is true then set ttl to 0
    IF updatestats THEN
        RAISE DEBUG 'Updatestats set to TRUE, setting TTL to 0';
        _stats_ttl := '0'::interval;
    END IF;

    -- If we don't need to calculate context, just return
    IF _context = 'off' THEN
        RETURN sw;
    END IF;

    -- Read current stats state without holding row locks during expensive
    -- estimate/count operations.
    SELECT * INTO sw FROM searches WHERE hash = inhash;

    IF sw IS NULL THEN
        -- In read-only mode, searches may not be persisted. Continue with
        -- non-persistent estimate/count calculation so context can still be
        -- returned to callers.
        sw.hash := inhash;
        sw._where := inwhere;
        sw_statslastupdated := NULL;
    ELSE
        sw_statslastupdated := sw.statslastupdated;
    END IF;

    -- If there is a cached row, figure out if we need to update
    IF
        sw IS NOT NULL
        AND sw.statslastupdated IS NOT NULL
        AND sw.context_count IS NOT NULL
        AND now() - sw.statslastupdated <= _stats_ttl
    THEN
        -- We have a cached row with data that is within our ttl.
        RAISE DEBUG 'Stats present in table and lastupdated within ttl: %', sw;
        RAISE DEBUG 'Returning cached counts. %', sw;
        RETURN sw;
    END IF;

    -- Calculate estimated cost and rows
    -- Use explain to get estimated count/cost
    RAISE DEBUG 'Calculating estimated stats';
    t := clock_timestamp();
    EXECUTE format('EXPLAIN (format json) SELECT 1 FROM items WHERE %s', inwhere)
        INTO explain_json;
    RAISE DEBUG 'Time for just the explain: %', clock_timestamp() - t;
    i := clock_timestamp() - t;

    sw_estimated_count := (explain_json->0->'Plan'->>'Plan Rows')::bigint;
    sw_estimated_cost := (explain_json->0->'Plan'->>'Total Cost')::float;

    RAISE DEBUG 'ESTIMATED_COUNT: %, THRESHOLD %', sw_estimated_count, _estimated_count_threshold;
    RAISE DEBUG 'ESTIMATED_COST: %, THRESHOLD %', sw_estimated_cost, _estimated_cost_threshold;

    -- If context is set to auto and the costs are within the threshold return the estimated costs
    IF
        _context = 'auto'
        AND sw_estimated_count >= _estimated_count_threshold
        AND sw_estimated_cost >= _estimated_cost_threshold
    THEN
        sw.context_count := sw_estimated_count;
        IF NOT ro THEN
            UPDATE searches SET
                statslastupdated = now(),
                context_count = sw.context_count
            WHERE
                hash = inhash
                AND statslastupdated IS NOT DISTINCT FROM sw_statslastupdated
            RETURNING * INTO sw;

            IF sw IS NULL THEN
                SELECT * INTO sw FROM searches WHERE hash = inhash;
            END IF;
        END IF;
        RAISE DEBUG 'Estimates are within thresholds, returning estimates. %', sw;
        RETURN sw;
    END IF;

    -- Calculate Actual Count
    t := clock_timestamp();
    RAISE NOTICE 'Calculating actual count...';
    EXECUTE format(
        'SELECT count(*) FROM items WHERE %s',
        inwhere
    ) INTO sw.context_count;
    i := clock_timestamp() - t;
    RAISE NOTICE 'Actual Count: % -- %', sw.context_count, i;

    IF NOT ro THEN
        UPDATE searches SET
            statslastupdated = now(),
            context_count = sw.context_count
        WHERE
            hash = inhash
            AND statslastupdated IS NOT DISTINCT FROM sw_statslastupdated
        RETURNING * INTO sw;

        IF sw IS NULL THEN
            SELECT * INTO sw FROM searches WHERE hash = inhash;
        END IF;
    END IF;
    RAISE DEBUG 'Returning with actual count. %', sw;
    RETURN sw;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;


-- ============================================================================
-- Search Cache Lifecycle (create, name, pin, GC)
-- ============================================================================

DROP FUNCTION IF EXISTS search_query(jsonb, boolean, jsonb);

CREATE OR REPLACE FUNCTION search_query(
    _search jsonb = '{}'::jsonb,
    updatestats boolean = false,
    _metadata jsonb = '{}'::jsonb
) RETURNS searches AS $$
DECLARE
    search searches%ROWTYPE;
    cached_search searches%ROWTYPE;
    search_where searches%ROWTYPE;
    ro boolean := pgstac.readonly();
BEGIN
    RAISE NOTICE 'SEARCH: %', _search;
    -- Calculate hash, where clause, and order by statement
    search.search := _search;
    search.metadata := _metadata;
    search._where := stac_search_to_where(_search);
    search.hash := search_hash_from_where(search._where, search.metadata);
    search.orderby := sort_sqlorderby(_search);
    search.lastused := now();
    search.usecount := 1;

    -- If we are in read only mode, directly return search
    IF ro THEN
        RETURN search;
    END IF;

    -- Cache bookkeeping is best-effort and non-blocking. We always return
    -- canonical hash + where, even if cache touch cannot be acquired quickly.
    UPDATE searches
    SET
        lastused = now(),
        usecount = searches.usecount + 1
    WHERE ctid = (
        SELECT ctid
        FROM searches
        WHERE hash = search.hash
        FOR UPDATE SKIP LOCKED
        LIMIT 1
    )
    RETURNING * INTO cached_search;

    IF cached_search IS NULL THEN
        IF pg_try_advisory_xact_lock(hashtext(search.hash)) THEN
            INSERT INTO searches (hash, search, _where, orderby, lastused, usecount, metadata)
                VALUES (search.hash, search.search, search._where, search.orderby, now(), 1, search.metadata)
                ON CONFLICT (hash) DO UPDATE SET
                    lastused = EXCLUDED.lastused,
                    usecount = searches.usecount + 1
                RETURNING * INTO cached_search;
        END IF;

        IF cached_search IS NULL THEN
            SELECT * INTO cached_search FROM searches WHERE hash = search.hash;
        END IF;
    END IF;

    IF cached_search IS NOT NULL THEN
        cached_search._where = search._where;
        cached_search.orderby = search.orderby;
        IF updatestats THEN
            search_where := where_stats(
                cached_search.hash,
                cached_search._where,
                true,
                _search->'conf'
            );
            cached_search.context_count := search_where.context_count;
            cached_search.statslastupdated := search_where.statslastupdated;
        END IF;
        RETURN cached_search;
    END IF;

    IF updatestats THEN
        search_where := where_stats(
            search.hash,
            search._where,
            true,
            _search->'conf'
        );
        search.context_count := search_where.context_count;
        search.statslastupdated := search_where.statslastupdated;
    END IF;

    RETURN search;

END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION search_fromhash(
    _hash text
) RETURNS searches AS $$
    SELECT * FROM searches WHERE hash = _hash LIMIT 1;
$$ LANGUAGE SQL STRICT;

CREATE OR REPLACE FUNCTION name_search(
    _search jsonb,
    _name text,
    _metadata jsonb DEFAULT '{}'::jsonb
) RETURNS searches AS $$
DECLARE
    named searches%ROWTYPE;
BEGIN
    named := search_query(_search, false, _metadata);
    UPDATE searches
    SET
        name = _name,
        lastused = now(),
        usecount = searches.usecount + 1
    WHERE hash = named.hash
    RETURNING * INTO named;

    IF named IS NULL THEN
        RAISE EXCEPTION 'Could not name search for input: %', _search;
    END IF;

    RETURN named;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION rename_search(_old_name text, _new_name text) RETURNS searches AS $$
DECLARE
    renamed searches%ROWTYPE;
BEGIN
    -- Serialize rename-pair operations to avoid deadlocks on concurrent name swaps.
    PERFORM pg_advisory_xact_lock(
        hashtext(
            least(_old_name, _new_name)
            || '|'
            || greatest(_old_name, _new_name)
        )
    );

    UPDATE searches
    SET
        name = _new_name,
        lastused = now(),
        usecount = searches.usecount + 1
    WHERE name = _old_name
    RETURNING * INTO renamed;

    IF renamed IS NULL THEN
        RAISE EXCEPTION 'Named search % not found', _old_name;
    END IF;

    RETURN renamed;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION unname_search(_name text) RETURNS searches AS $$
DECLARE
    unnamed searches%ROWTYPE;
BEGIN
    UPDATE searches
    SET
        name = NULL,
        pinned = false,
        lastused = now(),
        usecount = searches.usecount + 1
    WHERE name = _name
    RETURNING * INTO unnamed;

    IF unnamed IS NULL THEN
        RAISE EXCEPTION 'Named search % not found', _name;
    END IF;

    RETURN unnamed;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION pin_search(_name text) RETURNS searches AS $$
DECLARE
    pinned_search searches%ROWTYPE;
BEGIN
    UPDATE searches
    SET
        pinned = true,
        lastused = now(),
        usecount = searches.usecount + 1
    WHERE name = _name
    RETURNING * INTO pinned_search;

    IF pinned_search IS NULL THEN
        RAISE EXCEPTION 'Named search % not found', _name;
    END IF;

    RETURN pinned_search;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION unpin_search(_name text) RETURNS searches AS $$
DECLARE
    unpinned_search searches%ROWTYPE;
BEGIN
    UPDATE searches
    SET
        pinned = false,
        lastused = now(),
        usecount = searches.usecount + 1
    WHERE name = _name
    RETURNING * INTO unpinned_search;

    IF unpinned_search IS NULL THEN
        RAISE EXCEPTION 'Named search % not found', _name;
    END IF;

    RETURN unpinned_search;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION gc_anonymous_searches(retention_interval interval DEFAULT NULL, conf jsonb DEFAULT NULL) RETURNS bigint AS $$
    WITH effective_retention AS (
        SELECT COALESCE(
            retention_interval,
            search_gc_retention_interval(conf)
        ) AS i
    ),
    deleted AS (
        DELETE FROM searches
        USING effective_retention
        WHERE
            name IS NULL
            AND NOT pinned
            AND lastused < now() - effective_retention.i
        RETURNING 1
    )
    SELECT count(*)::bigint FROM deleted;
$$ LANGUAGE SQL SECURITY DEFINER;

CREATE OR REPLACE FUNCTION gc_search_caches(retention_interval interval DEFAULT NULL, conf jsonb DEFAULT NULL) RETURNS jsonb AS $$
    SELECT jsonb_build_object(
        'removed_searches',
        gc_anonymous_searches(retention_interval, conf)
    );
$$ LANGUAGE SQL SECURITY DEFINER;



-- fields_to_columns: Map a STAC `fields` include/exclude spec to a SQL projection
-- string for use in `row`-mode streaming queries.
--
-- The returned string is a comma-separated column list suitable for embedding
-- directly in a SELECT.  Control columns (id, collection, datetime,
-- end_datetime, fragment_id, item_hash, pgstac_updated_at, datetime_is_range,
-- private) are always included regardless of the fields spec because the client
-- needs them for rehydration, token minting, and ordering.
--
-- When no `include` list is supplied the function returns `i.*` plus correlated
-- subqueries for the fragment columns (frag_content, frag_links_template).
-- Fragment columns use correlated subqueries rather than JOIN aliases so the
-- returned projection string is self-contained: search_sql can use it in a
-- plain `FROM items i` query without adding item_fragments to the outer FROM
-- clause, which would cause column-ambiguity errors (both tables have `id` and
-- `collection`) in the WHERE clause generated by stac_search_to_where.
CREATE OR REPLACE FUNCTION fields_to_columns(fields jsonb DEFAULT '{}'::jsonb) RETURNS text AS $$
DECLARE
    includes text[];
    need_frag boolean;
    cols text[];
BEGIN
    includes := ARRAY(SELECT jsonb_array_elements_text(fields->'include'));

    -- Fast path: no include list → return everything.
    IF array_length(includes, 1) IS NULL THEN
        RETURN $proj$i.*,
            (SELECT content FROM item_fragments WHERE id = i.fragment_id) AS frag_content,
            (SELECT links_template FROM item_fragments WHERE id = i.fragment_id) AS frag_links_template$proj$;
    END IF;

    -- Control columns are always projected.
    cols := ARRAY[
        'i.id', 'i.collection', 'i.datetime', 'i.end_datetime',
        'i.fragment_id', 'i.item_hash', 'i.pgstac_updated_at',
        'i.datetime_is_range', 'i.private'
    ];

    -- Fragment is needed when any asset, link, or fragment-stored-property field
    -- is requested.  Over-including is safe; under-including breaks rehydration.
    need_frag := 'assets'      = ANY(includes)
              OR 'links'       = ANY(includes)
              OR 'properties'  = ANY(includes)
              OR EXISTS (
                    SELECT 1 FROM unnest(includes) AS inc
                    WHERE inc LIKE 'properties.%'
                 );

    -- Use array_append for single-element additions to avoid type-resolution
    -- ambiguity: `cols || 'literal'` with cols text[] causes PostgreSQL to
    -- attempt parsing the literal as an array literal, which fails.
    IF 'geometry'         = ANY(includes) THEN cols := array_append(cols, 'i.geometry'); END IF;
    IF 'bbox'             = ANY(includes) THEN cols := array_append(cols, 'i.bbox'); END IF;
    IF 'links'            = ANY(includes) THEN cols := cols || ARRAY['i.links', 'i.link_hrefs']; END IF;
    IF 'assets'           = ANY(includes) THEN cols := array_append(cols, 'i.assets'); END IF;
    IF 'extra'            = ANY(includes) THEN cols := array_append(cols, 'i.extra'); END IF;
    IF 'stac_version'     = ANY(includes) THEN cols := array_append(cols, 'i.stac_version'); END IF;
    IF 'stac_extensions'  = ANY(includes) THEN cols := array_append(cols, 'i.stac_extensions'); END IF;

    -- `properties` or `properties.<x>`: include the jsonb blob and all
    -- promoted scalar columns so the client can reassemble properties.
    IF 'properties' = ANY(includes)
    OR EXISTS (SELECT 1 FROM unnest(includes) AS inc WHERE inc LIKE 'properties.%')
    THEN
        cols := array_append(cols, 'i.properties');
        cols := cols || ARRAY(
            SELECT format('i.%I', p.property_path)
            FROM promoted_item_property_defs() p
        );
    ELSE
        -- Pull only the promoted columns explicitly requested as properties.*
        cols := cols || ARRAY(
            SELECT format('i.%I', p.property_path)
            FROM promoted_item_property_defs() p
            WHERE format('properties.%s', p.name) = ANY(includes)
        );
    END IF;

    IF need_frag THEN
        cols := cols || ARRAY[
            $fc$(SELECT content FROM item_fragments WHERE id = i.fragment_id) AS frag_content$fc$,
            $fl$(SELECT links_template FROM item_fragments WHERE id = i.fragment_id) AS frag_links_template$fl$
        ];
    END IF;

    RETURN array_to_string(cols, ', ');
END;
$$ LANGUAGE PLPGSQL STABLE PARALLEL SAFE;


-- collection_fragments_properties: does this collection's fragment_config fragment
-- any `properties.*` path? Used by fields_to_rowjsonb to decide whether a property
-- request needs the shared fragment. Conservative (TRUE) for an unknown / multi-
-- collection search (NULL arg) since we cannot prove the fragment is unneeded. The
-- default fragment_config fragments assets only, so this is FALSE for typical
-- collections — property requests then skip the fragment entirely.
CREATE OR REPLACE FUNCTION collection_fragments_properties(_collection text) RETURNS boolean AS $$
    SELECT CASE WHEN _collection IS NULL THEN true ELSE EXISTS (
        SELECT 1 FROM collections c, unnest(c.fragment_config) p
        WHERE c.id = _collection AND (fragment_path_array(p))[1] = 'properties'
    ) END;
$$ LANGUAGE sql STABLE;


-- fields_to_rowjsonb: row-mode jsonb projection that HONORS STAC `fields`
-- include/exclude, so a thin item does not drag heavy columns (geometry, assets,
-- properties, links) or the shared fragment over the wire. Used by search_page
-- row mode. Rules:
--   - Always ship the small control scalars the client needs to hydrate/serialize
--     and resume: id, collection, datetime, end_datetime, datetime_is_range,
--     fragment_id. (Keyset tokens come from search_page's separate `keys`, not
--     from this content.)
--   - Add a heavy column only when its field is requested (include) / not excluded.
--   - Fetch the inline `_fragment` ONLY when assets/links/properties/root-keys are
--     requested — those can live in the shared fragment (per fragment_config). This
--     is the deliberate "overfetch a little" (whole fragment) that saves a per-key
--     join, but it is skipped entirely for fields that never touch the fragment.
--   - Keys are raw column names; the client maps them to STAC exactly as
--     promoted_item_property_defs() / content_hydrate do. jsonb_strip_nulls keeps
--     null columns off the wire.
--   - Fragment-config precision for a SPECIFIC `properties.<x>` request: a promoted
--     property ships just its own column (not all ~37 promoted + the properties
--     jsonb); a non-promoted property pulls the per-item `properties` jsonb but
--     fetches the fragment ONLY if the collection's fragment_config actually
--     fragments properties (the default fragments assets only). The config lookup
--     runs at most once per search (not per row) and only for the property-request
--     case, so thinning never adds per-row work — see the timing in the 10M bench.
--     (item_field_registry is sample-based discovery, not an exhaustive existence
--     index, so it is NOT used to drop fields — that would risk losing real data.)
CREATE OR REPLACE FUNCTION fields_to_rowjsonb(
    fields jsonb DEFAULT '{}'::jsonb,
    _collections text[] DEFAULT NULL
) RETURNS text AS $$
DECLARE
    includes text[] := ARRAY(SELECT jsonb_array_elements_text(fields->'include'));
    excludes text[] := ARRAY(SELECT jsonb_array_elements_text(fields->'exclude'));
    has_inc boolean := array_length(includes, 1) IS NOT NULL;
    single_coll text := CASE WHEN array_length(_collections, 1) = 1 THEN _collections[1] ELSE NULL END;
    whole_props boolean;
    prop_reqs text[];          -- specific 'properties.<x>' names requested (x only)
    np_reqs text[];            -- of those, the non-promoted ones (need properties jsonb)
    props_fragmented boolean;
    parts text[] := ARRAY[
        $p$'id', i.id$p$, $p$'collection', i.collection$p$,
        $p$'datetime', i.datetime$p$, $p$'end_datetime', i.end_datetime$p$,
        $p$'datetime_is_range', i.datetime_is_range$p$, $p$'fragment_id', i.fragment_id$p$
    ];
    need_frag boolean := false;
BEGIN
    -- NOTE: text[] || 'literal' makes PostgreSQL parse the literal as an array
    -- literal (fails); use array_append for single elements, ARRAY[...] for pairs.
    -- geometry as clean STAC GeoJSON. NB: to_jsonb(i.geometry) emits PostGIS GeoJSON
    -- WITH a non-standard `crs` member (invalid for STAC); ST_AsGeoJson is the same
    -- server conversion cost but standards-clean, so the client gets a valid item
    -- directly. (A future WKB/typed-column row wire could offload this to the client;
    -- benchmark before switching.)
    IF (CASE WHEN has_inc THEN 'geometry' = ANY(includes) ELSE NOT ('geometry' = ANY(excludes)) END)
        THEN parts := array_append(parts, $p$'geometry', ST_AsGeoJson(i.geometry)::jsonb$p$); END IF;
    IF (CASE WHEN has_inc THEN 'bbox' = ANY(includes) ELSE NOT ('bbox' = ANY(excludes)) END)
        THEN parts := array_append(parts, $p$'bbox', i.bbox$p$); END IF;
    IF (CASE WHEN has_inc THEN 'assets' = ANY(includes) ELSE NOT ('assets' = ANY(excludes)) END)
        THEN parts := array_append(parts, $p$'assets', i.assets$p$); need_frag := true; END IF;
    IF (CASE WHEN has_inc THEN 'links' = ANY(includes) ELSE NOT ('links' = ANY(excludes)) END)
        THEN parts := parts || ARRAY[$p$'links', i.links$p$, $p$'link_hrefs', i.link_hrefs$p$]; need_frag := true; END IF;
    IF (CASE WHEN has_inc THEN 'stac_version' = ANY(includes) ELSE NOT ('stac_version' = ANY(excludes)) END)
        THEN parts := array_append(parts, $p$'stac_version', i.stac_version$p$); need_frag := true; END IF;
    IF (CASE WHEN has_inc THEN 'stac_extensions' = ANY(includes) ELSE NOT ('stac_extensions' = ANY(excludes)) END)
        THEN parts := array_append(parts, $p$'stac_extensions', i.stac_extensions$p$); need_frag := true; END IF;
    IF (CASE WHEN has_inc THEN 'extra' = ANY(includes) ELSE NOT ('extra' = ANY(excludes)) END)
        THEN parts := array_append(parts, $p$'extra', i.extra$p$); END IF;
    -- Properties. Three cases, increasingly precise:
    whole_props := (CASE WHEN has_inc THEN 'properties' = ANY(includes)
                                      ELSE NOT ('properties' = ANY(excludes)) END);
    prop_reqs := ARRAY(SELECT substring(x FROM 12) FROM unnest(includes) x WHERE x LIKE 'properties.%');

    IF whole_props THEN
        -- whole properties: per-item jsonb + every promoted column; fragment only if
        -- this collection fragments properties (single-coll) else conservative.
        parts := array_append(parts, $p$'properties', i.properties$p$);
        parts := parts || ARRAY(
            SELECT format('%L, i.%I', p.property_path, p.property_path)
            FROM promoted_item_property_defs() p);
        need_frag := need_frag OR collection_fragments_properties(single_coll);
    ELSIF array_length(prop_reqs, 1) IS NOT NULL THEN
        -- specific properties.<x>: ship only the promoted columns asked for ...
        parts := parts || ARRAY(
            SELECT format('%L, i.%I', p.property_path, p.property_path)
            FROM promoted_item_property_defs() p
            WHERE p.name = ANY(prop_reqs));
        -- ... and the per-item properties jsonb only if a NON-promoted prop is asked
        -- for (dropping any that the registry says the collection does not have).
        np_reqs := ARRAY(
            SELECT x FROM unnest(prop_reqs) x
            WHERE NOT EXISTS (SELECT 1 FROM promoted_item_property_defs() p WHERE p.name = x));
        -- NB: item_field_registry is a *sample-based* discovery index, not an
        -- exhaustive existence index (absence != nonexistent), so it is NOT used to
        -- drop a requested property — that would risk discarding real data. The
        -- authoritative precision signal is the collection's fragment_config below.
        IF array_length(np_reqs, 1) IS NOT NULL THEN
            parts := array_append(parts, $p$'properties', i.properties$p$);
            need_frag := need_frag OR collection_fragments_properties(single_coll);
        END IF;
    END IF;
    IF need_frag THEN
        parts := array_append(parts, $p$'_fragment', (SELECT to_jsonb(f) FROM item_fragments f WHERE f.id = i.fragment_id)$p$);
    END IF;
    -- jsonb_build_object caps at 100 args (50 key/value parts); the full-row case
    -- (all promoted columns) exceeds that, so emit chunks of <=40 parts and concat.
    DECLARE expr text := ''; lo int;
    BEGIN
        FOR lo IN 1 .. array_length(parts, 1) BY 40 LOOP
            expr := expr
                || CASE WHEN expr = '' THEN '' ELSE ' || ' END
                || 'jsonb_build_object('
                || array_to_string(parts[lo : LEAST(lo + 39, array_length(parts, 1))], ', ')
                || ')';
        END LOOP;
        RETURN 'jsonb_strip_nulls(' || expr || ')';
    END;
END;
$$ LANGUAGE PLPGSQL STABLE PARALLEL SAFE;


-- search_sql: Core streaming primitive — returns a SQL query string for the
-- given search, ready to be executed under a server-side cursor.
--
-- mode = 'item' (default): each projected row is a fully-hydrated STAC Feature
--   jsonb, computed by content_hydrate(i, f, fields).  The fragment join feeds
--   hydration without a per-row correlated subquery.
--
-- mode = 'row': each projected row is the raw split-storage columns plus inline
--   fragment content (fields_to_columns projection).  The client reassembles
--   items itself, offloading hydration CPU from the server.
--
-- The returned SQL MUST be consumed via a server-side cursor (DECLARE … FETCH),
-- never materialized with jsonb_agg or a plain SELECT … FROM (…).  A fast-start
-- cursor (cursor_tuple_fraction = 0) chooses Nested Loop + Merge Append instead
-- of Hash + Sort, enabling constant-memory streaming. (EXPLAIN of the whole query
-- without the cursor is misleading: it will show the Hash + Sort plan instead.)
CREATE OR REPLACE FUNCTION search_sql(
    _search jsonb DEFAULT '{}'::jsonb,
    mode text DEFAULT 'item'
) RETURNS text AS $$
DECLARE
    searches   searches%ROWTYPE;
    _where     text;
    _orderby   text;
    _fields    jsonb;
    token      record;
    token_where text;
    full_where text;
    projection text;
BEGIN
    searches  := search_query(_search);
    _where    := searches._where;
    _orderby  := searches.orderby;
    _fields   := coalesce(_search->'fields', '{}'::jsonb);

    -- Apply pagination token to WHERE and (for prev-token) reverse ORDER BY.
    token := get_token_record(_search->>'token');
    IF token IS NOT NULL THEN
        IF token.prev THEN
            _orderby := sort_sqlorderby(_search, TRUE);
        END IF;
        token_where := get_token_filter(_search->'sortby', token.item, token.prev, FALSE);
    END IF;

    full_where := concat_ws(' AND ', _where, token_where);
    IF full_where IS NULL OR trim(full_where) = '' THEN
        full_where := 'TRUE';
    END IF;

    IF mode = 'item' THEN
        -- Use a correlated subquery for the fragment so the outer FROM clause
        -- stays `FROM items i` only.  This avoids column-ambiguity errors:
        -- item_fragments also has `id` and `collection`, so a LEFT JOIN in
        -- the outer FROM would make the unqualified WHERE/ORDER BY references
        -- generated by stac_search_to_where and sort_sqlorderby ambiguous.
        projection := format(
            $p$content_hydrate(i, %L::jsonb, (SELECT f FROM item_fragments f WHERE f.id = i.fragment_id))$p$,
            _fields
        );
    ELSE
        -- row mode: fields_to_columns already generates correlated subqueries
        -- for frag_content / frag_links_template, so no JOIN needed here either.
        projection := fields_to_columns(_fields);
    END IF;

    RETURN format(
        $sql$
        SELECT %s
        FROM items i
        WHERE %s
        ORDER BY %s
        $sql$,
        projection,
        full_where,
        _orderby
    );
END;
$$ LANGUAGE PLPGSQL STABLE SECURITY DEFINER SET SEARCH_PATH TO pgstac, public;




-- search_cursor: Open a server-side cursor for streaming search results.
--
-- Usage (within a transaction):
--   SELECT search_cursor('{"collections":["sentinel-2"],"limit":1000}'::jsonb);
--   FETCH 1000 FROM pgstac_stream;
--   CLOSE pgstac_stream;  -- or just COMMIT
--
-- mode = 'item' (default): each FETCH row is a hydrated STAC Feature jsonb.
-- mode = 'row':            each FETCH row is raw split-storage columns + fragment.
-- cur:  cursor name, defaults to 'pgstac_stream'.
--
-- Opens a server-side cursor over the SQL text from search_sql(_search, mode).
DROP FUNCTION IF EXISTS search_cursor(jsonb);

CREATE OR REPLACE FUNCTION search_cursor(
    _search jsonb DEFAULT '{}'::jsonb,
    mode text DEFAULT 'item',
    cur refcursor DEFAULT 'pgstac_stream'
) RETURNS refcursor AS $$
BEGIN
    OPEN cur NO SCROLL FOR EXECUTE search_sql(_search, mode);
    RETURN cur;
END;
$$ LANGUAGE PLPGSQL SECURITY DEFINER SET SEARCH_PATH TO pgstac, public;


-- ============================================================================
-- v0.10 streaming search engine: keyset pagination + late-materialized walk.
-- search_page is the streaming entry point; search() (below) is re-derived onto it,
-- and geometrysearch()/xyzsearch() share the same discovery: all use chunker()
-- (above) to walk partition_stats bands from the predicate envelope -- no per-query
-- EXPLAIN and no materialized-view refresh on the hot path.
-- ============================================================================

-- NULL-aware encode/decode (override the simple versions).
CREATE OR REPLACE FUNCTION keyset_encode(vals text[]) RETURNS text AS $$
    SELECT encode(convert_to(array_to_string(vals, chr(31), chr(30)), 'UTF8'), 'base64');
$$ LANGUAGE sql IMMUTABLE;

CREATE OR REPLACE FUNCTION keyset_decode(token text) RETURNS text[] AS $$
    SELECT array_replace(
        string_to_array(convert_from(decode(token,'base64'),'UTF8'), chr(31)),
        chr(30), NULL);
$$ LANGUAGE sql IMMUTABLE;

-- Ordered sort keys = sortby + id + collection tiebreaks for a unique total order
-- (no overlapping pages), de-duplicated by field (first occurrence wins), each
-- resolved to its SQL expression.
CREATE OR REPLACE FUNCTION keyset_sortkeys(_search jsonb)
RETURNS TABLE(ord int, field text, expr text, dir text, notnull boolean) AS $$
    WITH base AS (
        SELECT coalesce(_search->'sortby','[{"field":"datetime","direction":"desc"}]'::jsonb) AS s
    ),
    app AS (
        SELECT s
               || jsonb_build_object('field','id','direction', s->0->>'direction')
               || jsonb_build_object('field','collection','direction', s->0->>'direction') AS s
        FROM base
    ),
    rows AS (
        SELECT value->>'field' AS field, get_sort_dir(value) AS dir, o
        FROM app, jsonb_array_elements(s) WITH ORDINALITY AS t(value, o)
    ),
    firsts AS (  -- keep first occurrence of each field
        SELECT DISTINCT ON (field) field, dir, o FROM rows ORDER BY field, o
    )
    -- id/collection/datetime/end_datetime are NOT NULL on items, so keyset_where can
    -- skip the NULL-handling branch for them (the common sort + tiebreaks).
    SELECT (row_number() OVER (ORDER BY o))::int, field, (queryable(field)).expression, dir,
           field IN ('id', 'collection', 'datetime', 'end_datetime')
    FROM firsts ORDER BY o;
$$ LANGUAGE sql STABLE;

-- Multi-level keyset seek predicate from token values (matches get_token_filter's
-- branch logic incl. NULLS FIRST/LAST, generalized to N levels & arbitrary fields).
CREATE OR REPLACE FUNCTION keyset_where(_search jsonb, _values text[], prev boolean DEFAULT false)
RETURNS text AS $$
DECLARE
    k record; vlit text; orterm text;
    andfilters text[] := '{}'::text[];
    orfilters  text[] := '{}'::text[];
BEGIN
    IF _values IS NULL THEN RETURN NULL; END IF;
    FOR k IN SELECT * FROM keyset_sortkeys(_search) ORDER BY ord LOOP
        vlit := CASE WHEN _values[k.ord] IS NULL THEN NULL ELSE quote_literal(_values[k.ord]) END;
        orterm := NULL;
        IF vlit IS NOT NULL AND ((prev AND k.dir='ASC') OR (NOT prev AND k.dir='DESC')) THEN
            orterm := format('(%s < %s)', k.expr, vlit);                          -- DESC fwd: nulls already passed
        ELSIF vlit IS NULL AND ((prev AND k.dir='ASC') OR (NOT prev AND k.dir='DESC')) THEN
            orterm := format('(%s IS NOT NULL)', k.expr);                         -- after a null (NULLS FIRST)
        ELSIF vlit IS NULL THEN
            orterm := NULL;                                                       -- after a null (NULLS LAST) → none
        ELSIF k.notnull THEN
            orterm := format('(%s > %s)', k.expr, vlit);                          -- NOT NULL column: no trailing nulls
        ELSE
            orterm := format('((%s > %s) OR (%s IS NULL))', k.expr, vlit, k.expr);-- ASC fwd: include trailing nulls
        END IF;
        IF orterm IS NOT NULL THEN
            IF array_length(andfilters,1) IS NULL THEN
                orfilters := orfilters || orterm;
            ELSE
                orfilters := orfilters || format('(%s AND %s)', array_to_string(andfilters,' AND '), orterm);
            END IF;
        END IF;
        andfilters := andfilters || CASE WHEN vlit IS NULL
            THEN format('(%s IS NULL)', k.expr) ELSE format('(%s = %s)', k.expr, vlit) END;
    END LOOP;
    IF array_length(orfilters,1) IS NULL THEN RETURN NULL; END IF;
    RETURN '(' || array_to_string(orfilters, ' OR ') || ')';
END;
$$ LANGUAGE plpgsql STABLE;

CREATE OR REPLACE FUNCTION search_page(
    _search jsonb DEFAULT '{}'::jsonb,
    _limit  int   DEFAULT 10,
    _token  text  DEFAULT NULL,
    _prev   boolean DEFAULT false,
    _mode   text  DEFAULT 'item'
) RETURNS jsonb AS $$
DECLARE
    _where text; _fields jsonb := coalesce(_search->'fields','{}'::jsonb);
    -- Per-row projection: 'item' hydrates server-side (FeatureCollection contract);
    -- 'row' ships the raw split-storage row + inline fragment for client-side
    -- hydration (the fast-start, low-memory streaming path the Rust client uses).
    -- Both modes share the SAME chunker / keyset / early-exit page machinery below,
    -- so 'row' inherits the newest-first early exit (fast TTFB, one page in memory).
    proj_expr text := CASE _mode
        WHEN 'row' THEN
            -- field-aware: only the columns the requested fields need + fragment-when-needed,
            -- with registry/fragment-config precision for property requests (collection-scoped).
            fields_to_rowjsonb(
                coalesce(_search->'fields','{}'::jsonb),
                ARRAY(SELECT jsonb_array_elements_text(_search->'collections')))
        ELSE
            format('content_hydrate(i, %L::jsonb, (SELECT f FROM item_fragments f WHERE f.id = i.fragment_id))',
                   coalesce(_search->'fields','{}'::jsonb))
    END;
    _hash text; ctx searches%ROWTYPE; total_count bigint;
    keyset_w text; full_where text;
    orderby_str text; keys_proj text; lead_field text; eff_lead_dir text;
    datetime_leading boolean;
    remaining int := _limit + 1; acc jsonb := '[]'::jsonb; cnt int := 0;
    r_count bigint := 0;
    has_more boolean := false;
    sdate timestamptz; edate timestamptz; q text; r record;
    first_k text[]; last_k text[]; fwd_first_k text[]; fwd_last_k text[];
    have_row boolean := false; nbands int := 0;
    band_pred text; next_tok text; prev_tok text; result jsonb;
    next_present boolean; prev_present boolean;
    _env pred_envelope;
BEGIN
    _where := stac_search_to_where(_search);                       -- PURE where/orderby derivation
    _hash  := search_hash_from_where(_where, '{}'::jsonb);
    -- discovery envelope: safe over-approximation of the search's (collections, datetime,
    -- end_datetime, geometry) extent, used by chunker() to prune partition_stats candidates.
    _env := search_envelope(_search);
    -- numberMatched (unchanged on/off/auto semantics). where_stats only persists and
    -- returns the count for a *registered* search, so register (best-effort, via
    -- search_query) only when context is actually wanted — keeping the default
    -- context='off' read path free of the cache write.
    IF context(_search->'conf') <> 'off' THEN
        PERFORM search_query(_search);
        total_count := (where_stats(_hash, _where, false, _search->'conf')).context_count;
    END IF;

    -- sort keys → EFFECTIVE ORDER BY (reversed for _prev), key projection, leading field/dir.
    -- For _prev we fetch the rows just *before* the token in reverse order, then flip.
    SELECT string_agg(expr||' '||CASE WHEN _prev THEN (CASE dir WHEN 'ASC' THEN 'DESC' ELSE 'ASC' END) ELSE dir END, ', ' ORDER BY ord),
           'ARRAY['||string_agg(format('(%s)::text', expr), ',' ORDER BY ord)||']::text[]',
           (array_agg(field ORDER BY ord))[1],
           (array_agg(CASE WHEN _prev THEN (CASE dir WHEN 'ASC' THEN 'DESC' ELSE 'ASC' END) ELSE dir END ORDER BY ord))[1]
    INTO orderby_str, keys_proj, lead_field, eff_lead_dir
    FROM keyset_sortkeys(_search);
    datetime_leading := (lead_field = 'datetime');

    -- keyset seek from token values (NO item lookup), arbitrary multi-level, direction-aware
    IF _token IS NOT NULL THEN
        keyset_w := keyset_where(_search, keyset_decode(_token), _prev);
    END IF;
    full_where := concat_ws(' AND ', _where, keyset_w);
    IF full_where IS NULL OR btrim(full_where) = '' THEN full_where := 'TRUE'; END IF;

    -- Fetch up to _limit+1 rows (the +1 tells us whether a further page exists in the
    -- walk direction) in EFFECTIVE order into a session temp table. Rows are appended
    -- SET-BASED (one INSERT per band / one for the direct query) and the page is built
    -- with a single jsonb_agg below -- this is O(n), unlike per-row jsonb `||` which is
    -- O(n^2) and explodes at high limits. The `ord` column carries the global effective
    -- order across bands (offset by the running count `cnt`).
    CREATE TEMP TABLE IF NOT EXISTS _search_page_rows (ord bigint, content jsonb, keys text[]);
    TRUNCATE _search_page_rows;
    IF datetime_leading THEN
        <<walk>>
        FOR sdate, edate IN
            EXECUTE format('SELECT s, e FROM chunker($1::pred_envelope) ORDER BY s %s',
                           CASE WHEN eff_lead_dir='ASC' THEN 'ASC' ELSE 'DESC' END)
            USING _env
        LOOP
            nbands := nbands + 1;
            band_pred := format('i.datetime >= %L AND i.datetime < %L', sdate, edate);
            EXECUTE format($q$
                INSERT INTO _search_page_rows (ord, content, keys)
                SELECT %s + row_number() OVER (ORDER BY %s),
                       %s,
                       %s
                FROM (SELECT * FROM items i WHERE (%s) AND (%s) ORDER BY %s LIMIT %s) i $q$,
                cnt, orderby_str, proj_expr, keys_proj, band_pred, full_where, orderby_str, remaining);
            GET DIAGNOSTICS r_count = ROW_COUNT;
            cnt := cnt + r_count;
            remaining := remaining - r_count;
            EXIT walk WHEN remaining <= 0;
        END LOOP;
    ELSE
        -- non-datetime-leading: single direct late-mat query (planner sorts, effective order)
        EXECUTE format($q$
            INSERT INTO _search_page_rows (ord, content, keys)
            SELECT row_number() OVER (ORDER BY %s),
                   %s,
                   %s
            FROM (SELECT * FROM items i WHERE (%s) ORDER BY %s LIMIT %s) i $q$,
            orderby_str, proj_expr, keys_proj, full_where, orderby_str, remaining);
        GET DIAGNOSTICS cnt = ROW_COUNT;
    END IF;

    -- Build the page (first _limit rows, effective order) with one O(n) jsonb_agg;
    -- derive the +1 has-more flag and the page's end keys from the materialized rows.
    -- (first_k/last_k are read as separate scalars -- array_agg of a text[] column makes
    -- a 2-D array whose single-subscript element is NULL, so it can't extract a key row.)
    has_more := cnt > _limit;
    have_row := cnt > 0;
    SELECT coalesce(jsonb_agg(content ORDER BY ord), '[]'::jsonb) INTO acc
    FROM (SELECT content, ord FROM _search_page_rows ORDER BY ord LIMIT _limit) z;
    IF have_row THEN
        SELECT keys INTO first_k FROM _search_page_rows ORDER BY ord LIMIT 1;
        SELECT keys INTO last_k  FROM _search_page_rows ORDER BY ord OFFSET (LEAST(_limit, cnt) - 1) LIMIT 1;
    END IF;

    -- Flip to forward sort order for _prev, and identify the page's forward end-rows.
    IF _prev THEN
        acc := flip_jsonb_array(acc);
        fwd_first_k := last_k; fwd_last_k := first_k;
        next_present := (_token IS NOT NULL);   -- a prev page always has the origin ahead
        prev_present := has_more;                -- ... and a further-back page iff more remain
    ELSE
        fwd_first_k := first_k; fwd_last_k := last_k;
        next_present := has_more;                -- a further page iff the +1 row existed
        prev_present := (_token IS NOT NULL);    -- a previous page iff we navigated off page 1
    END IF;

    IF have_row AND next_present THEN next_tok := keyset_encode(fwd_last_k); END IF;
    IF have_row AND prev_present THEN prev_tok := keyset_encode(fwd_first_k); END IF;

    result := jsonb_build_object(
        'type','FeatureCollection', 'features', acc,
        'numberReturned', jsonb_array_length(acc),
        'next', next_tok, 'prev', prev_tok, 'bands_scanned', nbands);
    IF total_count IS NOT NULL THEN
        result := result || jsonb_build_object('numberMatched', total_count);
    END IF;
    RETURN result;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path TO pgstac, public;

-- search_rows: binary counterpart of search_page's 'row' mode. Returns the raw
-- split-storage item rows (SETOF items -- native columns, geometry as EWKB on the wire,
-- no jsonb serialization) for one page, applying the SAME where + chunker discovery +
-- keyset seek + effective order + limit as a single streaming query (no temp table).
-- The client batch-loads fragments by fragment_id and hydrates client-side, and builds
-- the next/prev token from the sort-key values of the last/first row it received
-- (request _limit+1 to detect a further page). This is the fast, allocation-light path
-- the Rust client uses; search_page('...', 'row') is the jsonb equivalent.
CREATE OR REPLACE FUNCTION search_rows(
    _search jsonb DEFAULT '{}'::jsonb,
    _limit  int   DEFAULT NULL,
    _token  text  DEFAULT NULL,
    _prev   boolean DEFAULT false
) RETURNS SETOF items AS $$
DECLARE
    _where text; keyset_w text; full_where text;
    orderby_str text; lead_field text; datetime_leading boolean;
    _env pred_envelope;
    lim int := coalesce(_limit, nullif(get_setting('default_page_size', _search->'conf'), '')::int, 250);
BEGIN
    _where := stac_search_to_where(_search);
    _env := search_envelope(_search);
    SELECT string_agg(expr || ' ' || CASE WHEN _prev THEN (CASE dir WHEN 'ASC' THEN 'DESC' ELSE 'ASC' END) ELSE dir END, ', ' ORDER BY ord),
           (array_agg(field ORDER BY ord))[1]
    INTO orderby_str, lead_field
    FROM keyset_sortkeys(_search);
    datetime_leading := (lead_field = 'datetime');
    IF _token IS NOT NULL THEN
        keyset_w := keyset_where(_search, keyset_decode(_token), _prev);
    END IF;
    full_where := concat_ws(' AND ', _where, keyset_w);
    IF full_where IS NULL OR btrim(full_where) = '' THEN full_where := 'TRUE'; END IF;

    IF datetime_leading THEN
        -- per-band late-materialized fetch + outer merge (Merge Append), fast start.
        RETURN QUERY EXECUTE format($q$
            SELECT i.* FROM chunker($1::pred_envelope) AS bands(s, e)
            CROSS JOIN LATERAL (
                SELECT * FROM items i
                WHERE i.datetime >= bands.s AND i.datetime < bands.e AND (%s)
                ORDER BY %s LIMIT %s
            ) i
            ORDER BY %s LIMIT %s
        $q$, full_where, orderby_str, lim, orderby_str, lim) USING _env;
    ELSE
        RETURN QUERY EXECUTE format($q$
            SELECT * FROM items i WHERE (%s) ORDER BY %s LIMIT %s
        $q$, full_where, orderby_str, lim);
    END IF;
END;
$$ LANGUAGE plpgsql STABLE;

-- search() re-derived onto the streaming engine (search_page) with KEYSET tokens.
-- Preserves the FeatureCollection + links + numberMatched/numberReturned contract;
-- only the token VALUES in next/prev hrefs change (now opaque keyset, not collection:id).
-- Overrides the legacy search() in 004_search.sql (slated for removal in the cleanup step).
CREATE OR REPLACE FUNCTION search(_search jsonb DEFAULT '{}'::jsonb) RETURNS jsonb AS $$
DECLARE
    -- caller-provided limit is the max rows; default to the configurable target page size.
    _limit  int := coalesce((_search->>'limit')::int,
                            nullif(get_setting('default_page_size', _search->'conf'), '')::int, 250);
    _token  text := _search->>'token';
    is_prev boolean := _token LIKE 'prev:%';
    keyset  text := nullif(regexp_replace(coalesce(_token,''), '^(next|prev):', ''), '');
    page    jsonb;
    burl    text := rtrim(coalesce(base_url(_search->'conf'), ''), '/');
    links   jsonb := '[]'::jsonb;
    nt text; pt text; out jsonb;
BEGIN
    page := search_page(_search, _limit, keyset, is_prev);
    links := links
      || jsonb_build_object('rel','root','type','application/json','href', burl)
      || jsonb_build_object('rel','self','type','application/json','href', burl||'/search');
    nt := page->>'next'; pt := page->>'prev';
    IF nt IS NOT NULL THEN
        links := links || jsonb_build_object('rel','next','type','application/geo+json','method','GET',
            'href', burl||'/search?token=next:'||nt);
    END IF;
    IF pt IS NOT NULL THEN
        links := links || jsonb_build_object('rel','prev','type','application/geo+json','method','GET',
            'href', burl||'/search?token=prev:'||pt);
    END IF;
    out := jsonb_build_object(
        'type','FeatureCollection',
        'features', coalesce(page->'features','[]'::jsonb),
        'links', links,
        'numberReturned', page->'numberReturned');
    IF page ? 'numberMatched' THEN out := out || jsonb_build_object('numberMatched', page->'numberMatched'); END IF;
    RETURN out;
END;
$$ LANGUAGE plpgsql;
-- END FRAGMENT: 004_search.sql

-- BEGIN FRAGMENT: 004a_collectionsearch.sql
-- collections_asitems: Exposes collections as pseudo-items for CQL2 filtering.
-- The 'properties' column is the collection content with the standard top-level
-- STAC fields stripped, so CQL2 expressions like {"property":"title"} resolve
-- correctly when filtering collections via /collections?filter=... endpoints.
CREATE OR REPLACE VIEW collections_asitems AS
SELECT
    id,
    geometry,
    'collections' AS collection,
    datetime,
    end_datetime,
    -- Expose collection metadata as properties so CQL2 {"property":"title"} etc. work.
    content - '{links,assets,stac_version,stac_extensions}' AS properties,
    jsonb_build_object(
        'properties', content - '{links,assets,stac_version,stac_extensions}',
        'links', content->'links',
        'assets', content->'assets',
        'stac_version', content->'stac_version',
        'stac_extensions', content->'stac_extensions'
    ) AS content,
    content as collectionjson
FROM collections;


CREATE OR REPLACE FUNCTION collection_search_matched(
    IN _search jsonb DEFAULT '{}'::jsonb,
    OUT matched bigint
) RETURNS bigint AS $$
DECLARE
    _where text := stac_search_to_where(_search);
BEGIN
    EXECUTE format(
        $query$
            SELECT
                count(*)
            FROM
                collections_asitems
            WHERE %s
            ;
        $query$,
        _where
    ) INTO matched;
    RETURN;
END;
$$ LANGUAGE PLPGSQL STABLE PARALLEL SAFE;

CREATE OR REPLACE FUNCTION collection_search_rows(
    _search jsonb DEFAULT '{}'::jsonb
) RETURNS SETOF jsonb AS $$
DECLARE
    _where text := stac_search_to_where(_search);
    _limit int := coalesce((_search->>'limit')::int, 10);
    _fields jsonb := coalesce(_search->'fields', '{}'::jsonb);
    _orderby text;
    _offset int := COALESCE((_search->>'offset')::int, 0);
BEGIN
    _orderby := sort_sqlorderby(
        jsonb_build_object(
            'sortby',
            coalesce(
                _search->'sortby',
                '[{"field": "id", "direction": "asc"}]'::jsonb
            )
        )
    );
    RETURN QUERY EXECUTE format(
        $query$
            SELECT
                jsonb_fields(collectionjson, %L) as c
            FROM
                collections_asitems
            WHERE %s
            ORDER BY %s
            LIMIT %L
            OFFSET %L
            ;
        $query$,
        _fields,
        _where,
        _orderby,
        _limit,
        _offset
    );
END;
$$ LANGUAGE PLPGSQL;

CREATE OR REPLACE FUNCTION collection_search(
    _search jsonb DEFAULT '{}'::jsonb
) RETURNS jsonb AS $$
DECLARE
    out_records jsonb;
    number_matched bigint := collection_search_matched(_search);
    number_returned bigint;
    _limit int := coalesce((_search->>'limit')::float::int, 10);
    _offset int := coalesce((_search->>'offset')::float::int, 0);
    links jsonb := '[]';
    ret jsonb;
    base_url text:= concat(rtrim(base_url(_search->'conf'),'/'), '/collections');
    prevoffset int;
    nextoffset int;
BEGIN
    SELECT
        coalesce(jsonb_agg(c), '[]')
    INTO out_records
    FROM collection_search_rows(_search) c;

    number_returned := jsonb_array_length(out_records);
    RAISE DEBUG 'nm: %, nr: %, l:%, o:%', number_matched, number_returned, _limit, _offset;



    IF _limit <= number_matched AND number_matched > 0 THEN --need to have paging links
        nextoffset := least(_offset + _limit, number_matched - 1);
        prevoffset := greatest(_offset - _limit, 0);

        IF _offset > 0 THEN
            links := links || jsonb_build_object(
                    'rel', 'prev',
                    'type', 'application/json',
                    'method', 'GET' ,
                    'href', base_url,
                    'body', jsonb_build_object('offset', prevoffset),
                    'merge', TRUE
                );
        END IF;

        IF (_offset + _limit < number_matched)  THEN
            links := links || jsonb_build_object(
                    'rel', 'next',
                    'type', 'application/json',
                    'method', 'GET' ,
                    'href', base_url,
                    'body', jsonb_build_object('offset', nextoffset),
                    'merge', TRUE
                );
        END IF;

    END IF;

    ret := jsonb_build_object(
        'collections', out_records,
        'numberMatched', number_matched,
        'numberReturned', number_returned,
        'links', links
    );
    RETURN ret;

END;
$$ LANGUAGE PLPGSQL STABLE PARALLEL SAFE;
-- END FRAGMENT: 004a_collectionsearch.sql

-- BEGIN FRAGMENT: 005_tileutils.sql
SET SEARCH_PATH TO pgstac, public;

CREATE OR REPLACE FUNCTION tileenvelope(zoom int, x int, y int) RETURNS geometry AS $$
WITH t AS (
    SELECT
        20037508.3427892 as merc_max,
        -20037508.3427892 as merc_min,
        (2 * 20037508.3427892) / (2 ^ zoom) as tile_size
)
SELECT st_makeenvelope(
    merc_min + (tile_size * x),
    merc_max - (tile_size * (y + 1)),
    merc_min + (tile_size * (x + 1)),
    merc_max - (tile_size * y),
    3857
) FROM t;
$$ LANGUAGE SQL IMMUTABLE PARALLEL SAFE;DROP FUNCTION IF EXISTS mercgrid;


CREATE OR REPLACE FUNCTION ftime() RETURNS interval as $$
SELECT age(clock_timestamp(), transaction_timestamp());
$$ LANGUAGE SQL;
-- END FRAGMENT: 005_tileutils.sql

-- BEGIN FRAGMENT: 006_tilesearch.sql
SET SEARCH_PATH to pgstac, public;

DROP FUNCTION IF EXISTS geometrysearch;
CREATE OR REPLACE FUNCTION geometrysearch(
    IN geom geometry,
    IN queryhash text,
    IN fields jsonb DEFAULT NULL,
    IN _scanlimit int DEFAULT 10000,
    IN _limit int DEFAULT 100,
    IN _timelimit interval DEFAULT '5 seconds'::interval,
    IN exitwhenfull boolean DEFAULT TRUE, -- Return as soon as the passed in geometry is full covered
    IN skipcovered boolean DEFAULT TRUE -- Skip any items that would show up completely under the previous items
) RETURNS jsonb AS $$
DECLARE
    search searches%ROWTYPE;
    curs refcursor;
    _where text;
    query text;
    iter_record items%ROWTYPE;
    out_records jsonb := '[]'::jsonb;
    exit_flag boolean := FALSE;
    counter int := 1;
    scancounter int := 1;
    remaining_limit int := _scanlimit;
    tilearea float;
    unionedgeom geometry;
    clippedgeom geometry;
    unionedgeom_area float := 0;
    prev_area float := 0;
    -- v0.10 discovery: prune partition_stats by the search envelope (incl. the tile geom).
    _env pred_envelope;
    band_dir text;
    sdate timestamptz;
    edate timestamptz;
BEGIN
    DROP TABLE IF EXISTS pgstac_results;
    CREATE TEMP TABLE pgstac_results (content jsonb) ON COMMIT DROP;

    -- If the passed in geometry is not an area set exitwhenfull and skipcovered to false
    IF ST_GeometryType(geom) !~* 'polygon' THEN
        skipcovered = FALSE;
        exitwhenfull = FALSE;
    END IF;

    -- If skipcovered is true then you will always want to exit when the passed in geometry is full
    IF skipcovered THEN
        exitwhenfull := TRUE;
    END IF;

    search := search_fromhash(queryhash);

    IF search IS NULL THEN
        RAISE EXCEPTION 'Search with Query Hash % Not Found', queryhash;
    END IF;

    tilearea := st_area(geom);
    _where := format('%s AND st_intersects(geometry, %L::geometry)', search._where, geom);

    -- Build the discovery envelope from the registered search AND the tile geometry,
    -- then walk the chunker() over partition_stats for the discovery bands.
    _env := search_envelope(search.search);
    _env.geom := CASE
        WHEN _env.geom IS NULL THEN ST_Envelope(geom)
        ELSE ST_Envelope(ST_Intersection(_env.geom, ST_Envelope(geom)))
    END;
    band_dir := CASE WHEN search.orderby ILIKE '%datetime asc%' THEN 'ASC' ELSE 'DESC' END;

    <<bands>>
    FOR sdate, edate IN
        EXECUTE format('SELECT s, e FROM chunker($1::pred_envelope) ORDER BY s %s', band_dir)
        USING _env
    LOOP
        query := format(
            'SELECT * FROM items WHERE datetime >= %L AND datetime < %L AND %s ORDER BY %s LIMIT %L',
            sdate, edate, _where, search.orderby, remaining_limit
        );
        OPEN curs FOR EXECUTE query;
        LOOP
            FETCH curs INTO iter_record;
            EXIT WHEN NOT FOUND;
            IF exitwhenfull OR skipcovered THEN -- If we are not using exitwhenfull or skipcovered, we do not need to do expensive geometry operations
                clippedgeom := st_intersection(geom, iter_record.geometry);

                IF unionedgeom IS NULL THEN
                    unionedgeom := clippedgeom;
                ELSE
                    unionedgeom := st_union(unionedgeom, clippedgeom);
                END IF;

                unionedgeom_area := st_area(unionedgeom);

                IF skipcovered AND prev_area = unionedgeom_area THEN
                    scancounter := scancounter + 1;
                    CONTINUE;
                END IF;

                prev_area := unionedgeom_area;
            END IF;
            -- v0.10 split-storage: hydrate against the joined fragment.
            INSERT INTO pgstac_results (content) VALUES (
                content_hydrate(
                    iter_record,
                    fields,
                    (SELECT f FROM item_fragments f WHERE f.id = iter_record.fragment_id)
                )
            );

            IF counter >= _limit
                OR scancounter > _scanlimit
                OR ftime() > _timelimit
                OR (exitwhenfull AND unionedgeom_area >= tilearea)
            THEN
                exit_flag := TRUE;
                EXIT;
            END IF;
            counter := counter + 1;
            scancounter := scancounter + 1;

        END LOOP;
        CLOSE curs;
        EXIT bands WHEN exit_flag;
        remaining_limit := _scanlimit - scancounter;
    END LOOP;

    SELECT jsonb_agg(content) INTO out_records FROM pgstac_results WHERE content IS NOT NULL;

    RETURN jsonb_build_object(
        'type', 'FeatureCollection',
        'features', coalesce(out_records, '[]'::jsonb)
    );
END;
$$ LANGUAGE PLPGSQL;

DROP FUNCTION IF EXISTS geojsonsearch;
CREATE OR REPLACE FUNCTION geojsonsearch(
    IN geojson jsonb,
    IN queryhash text,
    IN fields jsonb DEFAULT NULL,
    IN _scanlimit int DEFAULT 10000,
    IN _limit int DEFAULT 100,
    IN _timelimit interval DEFAULT '5 seconds'::interval,
    IN exitwhenfull boolean DEFAULT TRUE,
    IN skipcovered boolean DEFAULT TRUE
) RETURNS jsonb AS $$
    SELECT * FROM geometrysearch(
        st_geomfromgeojson(geojson),
        queryhash,
        fields,
        _scanlimit,
        _limit,
        _timelimit,
        exitwhenfull,
        skipcovered
    );
$$ LANGUAGE SQL;

DROP FUNCTION IF EXISTS xyzsearch;
CREATE OR REPLACE FUNCTION xyzsearch(
    IN _x int,
    IN _y int,
    IN _z int,
    IN queryhash text,
    IN fields jsonb DEFAULT NULL,
    IN _scanlimit int DEFAULT 10000,
    IN _limit int DEFAULT 100,
    IN _timelimit interval DEFAULT '5 seconds'::interval,
    IN exitwhenfull boolean DEFAULT TRUE,
    IN skipcovered boolean DEFAULT TRUE
) RETURNS jsonb AS $$
    SELECT * FROM geometrysearch(
        st_transform(tileenvelope(_z, _x, _y), 4326),
        queryhash,
        fields,
        _scanlimit,
        _limit,
        _timelimit,
        exitwhenfull,
        skipcovered
    );
$$ LANGUAGE SQL;
-- END FRAGMENT: 006_tilesearch.sql

